type JobRow = {
  id: string;
  tenant_id: string;
  type: string;
  payload_json: any;
  attempts: number;
};

function toDigits(s: string) {
  return (s ?? "").replace(/\D/g, "");
}

function preprocessOcrTextSalesOrder(rawText: string) {
  const text = String(rawText ?? "");
  const lines = text
    .split(/\r?\n/)
    .map((l) => l.replace(/\s+/g, " ").trim())
    .filter(Boolean);

  // Heurística: em muitos pedidos (Agroforte), o cabeçalho contém telefone/endereço da empresa,
  // o que atrapalha a extração de telefone do cliente. Cortamos o texto até o início do formulário.
  const startIdx = lines.findIndex((l) =>
    /^\s*(local|nome|e-?mail|endere[cç]o|endere[cç]o\.|cidade|cep|estado|uf)\b/i.test(l)
  );

  const sliced = startIdx > 0 ? lines.slice(startIdx) : lines;

  // Remove resíduos de cabeçalho que, às vezes, vazam para as primeiras linhas.
  const filtered = sliced.filter((l, i) => {
    if (i > 10) return true;
    return !/(\bagroforte\b|\bcnpj\b|solu[cç]oes agr[ií]colas|\binscr\b|\bend(er)?e[cç]o\b.*\brua\b|\bfone\b)/i.test(
      l
    );
  });

  // Ignora o bloco "Condições Complementares" (ruído) mas preserva a área de assinatura/cliente.
  const out: string[] = [];
  let skippingConditions = false;

  for (const l of filtered) {
    if (!skippingConditions && /^condi[cç][õo]es\s+complementares\s*:?/i.test(l)) {
      skippingConditions = true;
      continue;
    }

    if (skippingConditions) {
      // quando chega na área de assinatura/cliente, voltamos a incluir
      if (/(\bdeclaro\b|\bdeclara\b|\bcliente\b\s*:|\bassinatura\b)/i.test(l)) {
        skippingConditions = false;
        out.push(l);
      }
      continue;
    }

    out.push(l);
  }

  return out.join("\n").trim();
}

function normalizeOcrTextForExtraction(rawText: string) {
  const text = String(rawText ?? "");
  // Só aplica "corte do cabeçalho" quando o documento aparenta ser o formulário da Agroforte.
  if (/\bagroforte\b/i.test(text) || (/\bcnpj\b/i.test(text) && /solu[cç]oes/i.test(text))) {
    return preprocessOcrTextSalesOrder(text);
  }
  return text;
}

function stripDiacritics(s: string) {
  try {
    return String(s ?? "")
      .normalize("NFD")
      .replace(/\p{Diacritic}/gu, "");
  } catch {
    return String(s ?? "");
  }
}

function normalizeKeyText(s: string) {
  return stripDiacritics(String(s ?? ""))
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function sanitizeExtractedValue(v: string) {
  return String(v ?? "")
    .replace(/[|]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function extractAgroforteCustomerFields(text: string) {
  const lines = String(text ?? "")
    .split(/\r?\n/)
    .map((l) => l.replace(/\s+/g, " ").trim())
    .filter(Boolean);

  const start = lines.findIndex((l) => /^local\s*:/i.test(l));
  if (start < 0) return null;

  // The items table usually starts around "Cód." / "Descrição".
  const endCandidates = [
    lines.findIndex((l) => /^c[oó]d\.?\b/i.test(l)),
    lines.findIndex((l) => /^descri[cç][aã]o\b/i.test(l)),
  ].filter((n) => n >= 0);

  const end = endCandidates.length ? Math.min(...endCandidates) : Math.min(lines.length, start + 18);
  const block = lines.slice(start, end).join("\n");

  const labels: Array<{ key: string; re: RegExp }> = [
    { key: "order_local", re: /\bLocal\s*:\s*/i },
    { key: "order_date_text", re: /\bData\s*:\s*/i },
    { key: "name", re: /\bNome\s*:\s*/i },
    { key: "customer_code", re: /\bC[oó]digo\s+do\s+Cliente\s*:\s*/i },
    { key: "email", re: /\bE-?mail\s*:\s*/i },
    { key: "birth_date_text", re: /\bData\s+de\s+Nascimento\s*:\s*/i },
    { key: "address", re: /\bEndere[cç]o\s*:\s*/i },
    { key: "phone_raw", re: /\bTelefone\s*:\s*/i },
    { key: "city", re: /\bCidade\s*:\s*/i },
    { key: "cep", re: /\bCEP\s*:\s*/i },
    { key: "state", re: /\bEstado\s*:\s*/i },
    { key: "inscr_est", re: /\bInscr\.?\s*Est\.?\s*:?\s*/i },
    { key: "rg", re: /\bRG\s*:?\s*/i },
    // In the form the label is "CNPJ/CPF" (bottom left)
    { key: "cpf_cnpj_raw", re: /\bCNPJ\s*\/\s*CPF\b\s*:?\s*/i },
    { key: "uf", re: /\bUF\b\s*:?\s*/i },
  ];

  // Collect all label hits with their positions.
  const hits: Array<{ key: string; start: number; end: number }> = [];
  for (const lb of labels) {
    const re = new RegExp(lb.re.source, lb.re.flags.includes("g") ? lb.re.flags : lb.re.flags + "g");
    let m: RegExpExecArray | null;
    while ((m = re.exec(block))) {
      hits.push({ key: lb.key, start: m.index, end: m.index + m[0].length });
      // only first hit for each key
      break;
    }
  }

  if (!hits.length) return null;
  hits.sort((a, b) => a.start - b.start);

  const out: Record<string, string> = {};
  for (let i = 0; i < hits.length; i++) {
    const cur = hits[i];
    const next = hits[i + 1];
    const slice = block.slice(cur.end, next ? next.start : block.length);
    const value = sanitizeExtractedValue(slice);
    if (value) out[cur.key] = value;
  }

  // Normalize CPF/CNPJ: keep digits only (we will still validate CPF length later).
  const cpfCnpjDigits = out.cpf_cnpj_raw ? toDigits(out.cpf_cnpj_raw) : "";
  if (cpfCnpjDigits) {
    if (cpfCnpjDigits.length === 11) out.cpf = cpfCnpjDigits;
    else out.cnpj = cpfCnpjDigits;
  }

  // Normalize UF/state to 2 letters when possible
  if (out.uf) {
    const uf = normalizeKeyText(out.uf).replace(/\s/g, "");
    if (/^[A-Z]{2}$/.test(uf)) out.uf = uf;
  }

  return out;
}

function extractFieldsFromText(text: string) {
  const agro = extractAgroforteCustomerFields(text) ?? {};

  const cpfMatch = text.match(/\b(\d{3}\.?(\d{3})\.?(\d{3})-?(\d{2}))\b/);
  const cpf = agro.cpf ?? (cpfMatch ? toDigits(cpfMatch[1]) : null);

  const rgMatch = text.match(/\bRG\s*[:\-]?\s*(\d{6,12})\b/i) ?? text.match(/\b(\d{7,10})\b/);
  const rg = agro.rg ? toDigits(agro.rg) : rgMatch ? toDigits(rgMatch[1]) : null;

  const birthMatch = text.match(/\b(\d{2}[\/-]\d{2}[\/-]\d{2,4})\b/);
  const birth_date_text = agro.birth_date_text ?? (birthMatch ? birthMatch[1] : null);

  const phoneMatch =
    text.match(/\bTelefone\s*[:\-]?\s*(\(?\d{2}\)?\s*9?\d{4}[-\s]?\d{4})\b/i) ??
    text.match(/\b(\(?\d{2}\)?\s*9?\d{4}[-\s]?\d{4})\b/);
  const phone_raw = agro.phone_raw ?? (phoneMatch ? phoneMatch[1] : null);

  const totalMatch = text.match(/R\$\s*([0-9\.,]{2,})/);
  const total_raw = totalMatch ? totalMatch[0] : null;

  const nameMatch = text.match(/\bNome\s*[:\-]\s*(.+)/i);
  const name = agro.name ?? (nameMatch ? nameMatch[1].trim().slice(0, 80) : null);

  const signaturePresent = /assinatura/i.test(text);

  // Items (very rough): lines with qty and value
  const lines = text
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter(Boolean);
  const itemLines = lines.filter((l) => /\b(\d+[\.,]?\d*)\b/.test(l) && /R\$/.test(l));

  return {
    name,
    cpf,
    // we store rg as digits-only (existing behavior)
    rg,
    birth_date_text,
    phone_raw,
    total_raw,
    signaturePresent,
    itemLines: itemLines.slice(0, 15),

    // Agroforte-specific fields
    customer_code: agro.customer_code ?? null,
    email: agro.email ?? null,
    address: agro.address ?? null,
    city: agro.city ?? null,
    cep: agro.cep ?? null,
    state: agro.state ?? null,
    uf: agro.uf ?? null,
    order_local: agro.order_local ?? null,
    order_date_text: agro.order_date_text ?? null,
    inscr_est: agro.inscr_est ?? null,
  };
}

function parsePtBrMoneyToCents(input: string | null | undefined) {
  const raw = String(input ?? "");
  const m = raw.match(/([0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2})/);
  if (!m?.[1]) return null;
  const normalized = m[1].replace(/\./g, "").replace(/,/g, ".");
  const n = Number(normalized);
  if (!Number.isFinite(n)) return null;
  return Math.round(n * 100);
}

function extractTotalCents(text: string) {
  const t = String(text ?? "");
  // Prefer explicit TOTAL label
  const labeled = t.match(/\bTOTAL\b[^\d]{0,30}([0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2})/i);
  if (labeled?.[1]) return parsePtBrMoneyToCents(labeled[1]);

  // Fallback: first currency-like occurrence
  const rs = t.match(/R\$\s*([0-9]{1,3}(?:\.[0-9]{3})*,[0-9]{2})/i);
  if (rs?.[1]) return parsePtBrMoneyToCents(rs[1]);

  return null;
}



async function computeSalesOrderFingerprint(args: {
  clientKey: string;
  totalCents: number;
  itemLines: string[];
}) {
  const clientKey = normalizeKeyText(args.clientKey);
  const totalCents = Number(args.totalCents);
  const itemKey = args.itemLines
    .map((l) => normalizeKeyText(l))
    .filter(Boolean)
    .join(" | ");

  // Para evitar falso-positivo, só deduplica quando temos:
  // - cliente (cpf/telefone/nome) + total + ao menos 1 linha de item
  if (!clientKey || !Number.isFinite(totalCents) || totalCents <= 0) return null;
  if (!itemKey || itemKey.length < 8) return null;

  const base = `${clientKey}::${totalCents}::${itemKey}`;
  return await sha256Hex(base);
}

async function mergeDuplicateCase(args: {
  supabase: any;
  tenantId: string;
  duplicateCaseId: string;
  keepCaseId: string;
  fingerprint: string;
}) {
  const { supabase, tenantId, duplicateCaseId, keepCaseId, fingerprint } = args;

  // Move entities to the kept case (best-effort)
  await supabase
    .from("wa_messages")
    .update({ case_id: keepCaseId })
    .eq("tenant_id", tenantId)
    .eq("case_id", duplicateCaseId);
  await supabase
    .from("case_attachments")
    .update({ case_id: keepCaseId })
    .eq("tenant_id", tenantId)
    .eq("case_id", duplicateCaseId);
  await supabase
    .from("pendencies")
    .update({ case_id: keepCaseId })
    .eq("tenant_id", tenantId)
    .eq("case_id", duplicateCaseId);

  // IMPORTANT: don't duplicate items.
  // If the kept case already has items, we discard the duplicate case's items.
  // If it doesn't, we move them.
  const { data: keepAnyItem } = await supabase
    .from("case_items")
    .select("id")
    .eq("case_id", keepCaseId)
    .limit(1)
    .maybeSingle();

  if ((keepAnyItem as any)?.id) {
    await supabase.from("case_items").delete().eq("case_id", duplicateCaseId);
  } else {
    await supabase.from("case_items").update({ case_id: keepCaseId }).eq("case_id", duplicateCaseId);
  }

  // Keep case_fields history (may contain duplicates; acceptable for now)
  await supabase.from("case_fields").update({ case_id: keepCaseId }).eq("case_id", duplicateCaseId);

  // Soft-delete duplicate case
  await supabase
    .from("cases")
    .update({ deleted_at: new Date().toISOString() })
    .eq("tenant_id", tenantId)
    .eq("id", duplicateCaseId);

  // Audit
  await supabase.from("timeline_events").insert({
    tenant_id: tenantId,
    case_id: keepCaseId,
    event_type: "duplicate_detected",
    actor_type: "system",
    actor_id: null,
    message: "Pedido duplicado detectado. Consolidamos mensagens/anexos no caso existente.",
    meta_json: { duplicate_case_id: duplicateCaseId, fingerprint },
    occurred_at: new Date().toISOString(),
  });
}

async function runOcrGoogleVision(imageUrl: string) {
  const apiKey = Deno.env.get("GOOGLE_VISION_API_KEY") ?? "";
  if (!apiKey) return { ok: false as const, error: "Missing GOOGLE_VISION_API_KEY" };

  const content = await fetchAsBase64(imageUrl);
  const endpoint = `https://vision.googleapis.com/v1/images:annotate?key=${encodeURIComponent(apiKey)}`;
  const visionReq = {
    requests: [
      {
        image: { content },
        features: [{ type: "DOCUMENT_TEXT_DETECTION" }],
      },
    ],
  };

  const res = await fetch(endpoint, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(visionReq),
  });

  const json = await res.json().catch(() => null);
  if (!res.ok || !json) {
    return { ok: false as const, error: `Vision API error: ${res.status}`, raw: json };
  }

  const annotation = json?.responses?.[0]?.fullTextAnnotation;
  const text = annotation?.text ?? "";

  return { ok: true as const, text, raw: json?.responses?.[0] ?? json };
}

function addDays(dateStr: string, days: number) {
  const [y, m, d] = dateStr.split("-").map((n) => Number(n));
  const base = new Date(Date.UTC(y, (m ?? 1) - 1, d ?? 1, 12, 0, 0));
  base.setUTCDate(base.getUTCDate() + days);
  const yy = base.getUTCFullYear();
  const mm = String(base.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(base.getUTCDate()).padStart(2, "0");
  return `${yy}-${mm}-${dd}`;
}

function tzOffsetMs(date: Date, timeZone: string) {
  const dtf = new Intl.DateTimeFormat("en-US", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hourCycle: "h23",
  });
  const parts = dtf.formatToParts(date);
  const map: any = {};
  for (const p of parts) map[p.type] = p.value;

  const asUtc = Date.UTC(
    Number(map.year),
    Number(map.month) - 1,
    Number(map.day),
    Number(map.hour),
    Number(map.minute),
    Number(map.second)
  );

  return asUtc - date.getTime();
}

function localMidnightUtcMs(dateStr: string, timeZone: string) {
  const [y, m, d] = dateStr.split("-").map((n) => Number(n));
  const guess = Date.UTC(y, m - 1, d, 0, 0, 0);

  // Two-pass correction (handles DST shifts if they ever exist again)
  let t = guess;
  let off = tzOffsetMs(new Date(t), timeZone);
  t = guess - off;
  off = tzOffsetMs(new Date(t), timeZone);
  t = guess - off;

  return t;
}

function buildDailyTopics(text: string) {
  const stop = new Set([
    "de",
    "da",
    "do",
    "das",
    "dos",
    "e",
    "a",
    "o",
    "os",
    "as",
    "que",
    "pra",
    "para",
    "com",
    "na",
    "no",
    "em",
    "um",
    "uma",
    "uns",
    "umas",
    "por",
    "se",
    "não",
    "sim",
    "oi",
    "ola",
    "olá",
    "boa",
    "bom",
    "dia",
    "tarde",
    "noite",
  ]);

  const words = (text ?? "")
    .toLowerCase()
    .replace(/https?:\/\/\S+/g, " ")
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .split(/\s+/)
    .map((w) => w.trim())
    .filter(Boolean)
    .filter((w) => w.length >= 4)
    .filter((w) => !stop.has(w));

  const freq = new Map<string, number>();
  for (const w of words) freq.set(w, (freq.get(w) ?? 0) + 1);

  const top = Array.from(freq.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([w]) => w);

  return top;
}

function normalizeDescription(s: string) {
  const raw = String(s ?? "");
  try {
    return raw
      .normalize("NFD")
      .replace(/\p{Diacritic}/gu, "")
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .replace(/\s+/g, " ")
      .trim();
  } catch {
    return raw
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .replace(/\s+/g, " ")
      .trim();
  }
}

function parseDateLoose(s: string): string | null {
  const v = String(s ?? "").trim();
  if (!v) return null;

  // YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;

  // DD/MM/YYYY or DD/MM/YY
  const m = v.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
  if (m) {
    const dd = String(m[1]).padStart(2, "0");
    const mm = String(m[2]).padStart(2, "0");
    let yyyy = m[3];
    if (yyyy.length === 2) yyyy = `20${yyyy}`;
    return `${yyyy}-${mm}-${dd}`;
  }

  // fallback: try Date
  const d = new Date(v);
  if (!Number.isNaN(d.getTime())) {
    const y = d.getUTCFullYear();
    const mo = String(d.getUTCMonth() + 1).padStart(2, "0");
    const da = String(d.getUTCDate()).padStart(2, "0");
    return `${y}-${mo}-${da}`;
  }

  return null;
}

function parseOfxDateLoose(s: string): string | null {
  // OFX usually: YYYYMMDD or YYYYMMDDHHMMSS[...]
  const v = String(s ?? "").trim();
  const m = v.match(/^(\d{4})(\d{2})(\d{2})/);
  if (!m) return parseDateLoose(v);
  return `${m[1]}-${m[2]}-${m[3]}`;
}

function extractOfxTag(block: string, tag: string) {
  const re = new RegExp(`<${tag}>([^<\r\n]*)`, "i");
  const m = String(block ?? "").match(re);
  return (m?.[1] ?? "").trim();
}

function parseOfx(text: string) {
  const raw = String(text ?? "");
  const blocks = raw.match(/<STMTTRN>[\s\S]*?<\/STMTTRN>/gi) ?? [];

  const rows: Record<string, string>[] = [];

  for (const b of blocks) {
    const dt = extractOfxTag(b, "DTPOSTED");
    const txDate = parseOfxDateLoose(dt);
    if (!txDate) continue;

    const amt = extractOfxTag(b, "TRNAMT");
    const memo = extractOfxTag(b, "MEMO") || extractOfxTag(b, "NAME");

    // Keep OFX identifiers in raw_payload for traceability
    const fitid = extractOfxTag(b, "FITID");
    const refnum = extractOfxTag(b, "REFNUM");
    const checknum = extractOfxTag(b, "CHECKNUM");

    rows.push({
      transaction_date: txDate,
      description: memo,
      amount: amt,
      fitid,
      refnum,
      checknum,
    });
  }

  return { headers: [] as string[], rows };
}

function parseCsv(text: string) {
  const lines = String(text ?? "")
    .replace(/^\uFEFF/, "")
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter((l) => l.length > 0);
  if (lines.length < 2) return { headers: [] as string[], rows: [] as Record<string, string>[] };

  const splitLine = (line: string) => {
    // MVP: supports commas/semicolons, minimal quote support
    const sep = line.includes(";") && !line.includes(",") ? ";" : ",";
    const out: string[] = [];
    let cur = "";
    let inQ = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') {
        inQ = !inQ;
        continue;
      }
      if (!inQ && ch === sep) {
        out.push(cur);
        cur = "";
        continue;
      }
      cur += ch;
    }
    out.push(cur);
    return out.map((s) => s.trim());
  };

  const headers = splitLine(lines[0]).map((h) => normalizeDescription(h).replace(/\s/g, "_"));
  const rows: Record<string, string>[] = [];
  for (const line of lines.slice(1)) {
    const parts = splitLine(line);
    const row: Record<string, string> = {};
    for (let i = 0; i < headers.length; i++) {
      row[headers[i]] = String(parts[i] ?? "").trim();
    }
    rows.push(row);
  }
  return { headers, rows };
}

function pickField(row: Record<string, string>, keys: string[]) {
  for (const k of keys) {
    if (row[k] != null && String(row[k]).trim() !== "") return String(row[k]);
  }
  return "";
}

function parseAmountLoose(s: string): number | null {
  const v = String(s ?? "").trim();
  if (!v) return null;

  // Remove currency and spaces
  let t = v.replace(/[^0-9,\.-]/g, "").trim();

  // If it has both '.' and ',', decide decimal by last separator
  const lastDot = t.lastIndexOf(".");
  const lastComma = t.lastIndexOf(",");
  if (lastDot >= 0 && lastComma >= 0) {
    const decSep = lastDot > lastComma ? "." : ",";
    const thouSep = decSep === "." ? "," : ".";
    t = t.split(thouSep).join("");
    if (decSep === ",") t = t.replace(",", ".");
  } else if (lastComma >= 0 && lastDot < 0) {
    // Assume comma is decimal
    t = t.replace(/\./g, "").replace(",", ".");
  }

  const n = Number(t);
  if (Number.isNaN(n)) return null;
  return n;
}

async function processFinancialIngestionJob(opts: {
  supabase: any;
  tenantId: string;
  ingestionJobId: string;
  bucket: string;
  path: string;
}) {
  const { supabase, tenantId, ingestionJobId, bucket, path } = opts;

  await supabase.from("ingestion_jobs").update({ status: "processing", error_log: null }).eq("id", ingestionJobId);

  // Fetch file
  const { data: dl, error: dlErr } = await supabase.storage.from(bucket).download(path);
  if (dlErr || !dl) throw new Error(`download_failed:${dlErr?.message ?? "unknown"}`);

  const bytes = new Uint8Array(await dl.arrayBuffer());
  const text = new TextDecoder().decode(bytes);

  // PIPELINE: upload → parse → normalize → deduplicate → persist
  const isOfx =
    /\n\s*OFXHEADER\s*:/i.test(text) ||
    /<OFX[>\s]/i.test(text) ||
    /<STMTTRN>/i.test(text) ||
    path.toLowerCase().endsWith(".ofx");

  const parsed = isOfx ? parseOfx(text) : parseCsv(text);

  // Ensure we have at least one bank account to attach transactions.
  // If tenant has none, create a default one.
  let accountId: string | null = null;
  {
    const { data: acc } = await supabase
      .from("bank_accounts")
      .select("id")
      .eq("tenant_id", tenantId)
      .order("created_at", { ascending: true })
      .limit(1)
      .maybeSingle();
    accountId = (acc as any)?.id ?? null;
  }

  if (!accountId) {
    const { data: created, error: cErr } = await supabase
      .from("bank_accounts")
      .insert({
        tenant_id: tenantId,
        bank_name: "Import",
        account_name: "Conta padrão (import)",
        account_type: "checking",
        currency: "BRL",
      })
      .select("id")
      .maybeSingle();
    if (cErr || !created?.id) throw new Error(`failed_to_create_default_account:${cErr?.message ?? ""}`);
    accountId = created.id;
  }

  const occurrenceMap = new Map<string, number>();
  const inserts: any[] = [];
  const errors: string[] = [];

  // Simple header mapping (works for common exports)
  const dateKeys = ["data", "date", "transaction_date", "dt", "data_mov", "data_lancamento"];
  const descKeys = ["descricao", "description", "historico", "memo", "narrativa", "desc"];
  const amountKeys = ["valor", "amount", "montante", "value", "vlr"];
  const creditKeys = ["credito", "credit"];
  const debitKeys = ["debito", "debit"];

  for (const row of parsed.rows) {
    const dateRaw = pickField(row, dateKeys);
    const txDate = parseDateLoose(dateRaw);
    if (!txDate) {
      errors.push(`invalid_date:${dateRaw}`);
      continue;
    }

    const descRaw = pickField(row, descKeys);
    const descNorm = normalizeDescription(descRaw);

    // Amount can be in one column or split credit/debit
    let amt = parseAmountLoose(pickField(row, amountKeys));
    let inferredType: "credit" | "debit" = "debit";

    if (amt == null) {
      const cr = parseAmountLoose(pickField(row, creditKeys));
      const db = parseAmountLoose(pickField(row, debitKeys));
      if (cr != null) {
        amt = Math.abs(cr);
        inferredType = "credit";
      } else if (db != null) {
        amt = Math.abs(db);
        inferredType = "debit";
      }
    } else {
      // If amount is signed (common in exports / OFX), infer type from sign.
      inferredType = amt >= 0 ? "credit" : "debit";
    }

    if (amt == null) {
      errors.push(`invalid_amount:${JSON.stringify(row)}`);
      continue;
    }

    // Normalize sign
    if (amt < 0) {
      inferredType = "debit";
      amt = Math.abs(amt);
    }

    const baseKey = JSON.stringify({
      transaction_date: txDate,
      amount: Number(amt.toFixed(2)),
      description: descNorm,
    });
    const occurrence = (occurrenceMap.get(baseKey) ?? 0) + 1;
    occurrenceMap.set(baseKey, occurrence);

    const isUuidFitid = row.fitid && /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(row.fitid);
    const fingerprint = await sha256Hex(
      JSON.stringify({
        tenant_id: tenantId,
        account_id: accountId,
        transaction_date: txDate,
        amount: Number(amt.toFixed(2)),
        description: descNorm,
        occurrence,
        fitid: isUuidFitid ? undefined : (row.fitid || undefined),
      })
    );

    inserts.push({
      tenant_id: tenantId,
      account_id: accountId,
      amount: Number(amt.toFixed(2)),
      type: inferredType,
      description: descRaw,
      transaction_date: txDate,
      competence_date: txDate,
      status: "posted",
      fingerprint,
      source: "import",
      raw_payload: { format: isOfx ? "ofx" : "csv", ...row },
    });
  }

  const chunkSize = 250;
  let inserted = 0;

  for (let i = 0; i < inserts.length; i += chunkSize) {
    const chunk = inserts.slice(i, i + chunkSize);

    const { data, error } = await supabase
      .from("financial_transactions")
      .upsert(chunk, { onConflict: "tenant_id,fingerprint", ignoreDuplicates: true })
      .select("id");

    if (error) {
      // Most likely: missing columns / CSV mismatch
      throw new Error(`persist_failed:${error.message}`);
    }

    inserted += (data ?? []).length;

    await supabase
      .from("ingestion_jobs")
      .update({ processed_rows: inserted, status: "processing" })
      .eq("id", ingestionJobId);
  }

  const errLog = errors.length ? errors.slice(0, 30).join("\n") : null;

  await supabase
    .from("ingestion_jobs")
    .update({ status: "done", processed_rows: inserted, error_log: errLog })
    .eq("id", ingestionJobId);

  return { ok: true, inserted, parsedRows: parsed.rows.length, errors: errors.length };
}

async function getTenantTensionRule(supabase: any, tenantId: string, tensionType: string) {
  const { data } = await supabase
    .from("tenant_tension_rules")
    .select("threshold,severity")
    .eq("tenant_id", tenantId)
    .eq("tension_type", tensionType)
    .order("created_at", { ascending: false })
    .limit(1)
    .maybeSingle();
  return data as any | null;
}

function clamp(n: number, a: number, b: number) {
  return Math.max(a, Math.min(b, n));
}

function computeScores(opts: { impact: number; urgency: number; cascade: number }) {
  const impact = clamp(opts.impact, 0, 100);
  const urgency = clamp(opts.urgency, 0, 100);
  const cascade = clamp(opts.cascade, 0, 100);
  const final = clamp(impact * 0.5 + urgency * 0.35 + cascade * 0.15, 0, 100);
  return { impact, urgency, cascade, final };
}

async function ensureDecisionCardFromTension(opts: {
  supabase: any;
  tenantId: string;
  tensionEventId: string;
  tensionType: string;
  description: string;
  severity: string;
  referenceId?: string | null;
}) {
  const { supabase, tenantId, tensionEventId, tensionType, description, severity, referenceId } = opts;

  // Rule critical: do NOT create card if there is no actionable recommendation.
  const actions: Array<{ title: string; detail?: string }> = [];
  let title = "Decisão financeira";
  let dueDate: string | null = null;

  if (tensionType === "cash_negative") {
    title = "Evitar caixa negativo";
    dueDate = addDaysIsoDate(new Date().toISOString().slice(0, 10), 2);

    actions.push({
      title: "Priorizar recebíveis",
      detail: "Liste recebíveis e acione cobranças/antecipações para recuperar caixa rapidamente.",
    });
    actions.push({
      title: "Renegociar pagáveis",
      detail: "Negocie prazos/parcelamentos com fornecedores para aliviar o curto prazo.",
    });
    actions.push({
      title: "Cortar gastos não essenciais",
      detail: "Revise despesas variáveis e congele o que não for crítico.",
    });
  }

  if (tensionType === "runway_low") {
    title = "Aumentar runway de caixa";
    dueDate = addDaysIsoDate(new Date().toISOString().slice(0, 10), 7);

    actions.push({
      title: "Ajustar orçamento",
      detail: "Revise orçamento e reduza custos que estejam acima do planejado.",
    });
    actions.push({
      title: "Acelerar entradas",
      detail: "Antecipar recebíveis e melhorar prazos de pagamento de clientes.",
    });
  }

  if (tensionType === "revenue_not_received") {
    title = "Cobrar receita em atraso";
    dueDate = addDaysIsoDate(new Date().toISOString().slice(0, 10), 3);

    // Actionable only if reference is a receivable (we set reference_id to the oldest overdue id).
    if (referenceId) {
      actions.push({
        title: "Contatar cliente e negociar pagamento",
        detail: `Recebível em atraso (ref: ${String(referenceId).slice(0, 8)}…). Registrar acordo e novo vencimento se necessário.`,
      });
    }
    actions.push({
      title: "Revisar política de crédito",
      detail: "Reavaliar prazos/condições para reduzir inadimplência recorrente.",
    });
  }

  if (tensionType === "budget_deviation") {
    title = "Corrigir desvio de orçamento";
    dueDate = addDaysIsoDate(new Date().toISOString().slice(0, 10), 10);

    actions.push({
      title: "Identificar origem do excesso",
      detail: "Revise transações recentes categorizadas e identifique o que elevou o custo.",
    });
    actions.push({
      title: "Replanejar ou reduzir custo",
      detail: "Se o gasto foi necessário, atualize o orçamento; caso contrário, reduza e bloqueie recorrências.",
    });
  }

  if (actions.length === 0) return { ok: true, skipped: true, reason: "no_action" };

  // Avoid duplicates: unique (tenant_id, tension_event_id)
  const { data: existing } = await supabase
    .from("financial_decision_cards")
    .select("id")
    .eq("tenant_id", tenantId)
    .eq("tension_event_id", tensionEventId)
    .limit(1);

  if ((existing ?? []).length) return { ok: true, skipped: true, reason: "already_exists" };

  const { data: created, error } = await supabase
    .from("financial_decision_cards")
    .insert({
      tenant_id: tenantId,
      tension_event_id: tensionEventId,
      title,
      description,
      severity: severity || "medium",
      recommended_actions: actions,
      status: "open",
      owner: null,
      due_date: dueDate,
    })
    .select("id")
    .maybeSingle();

  if (error || !created?.id) throw new Error(`financial_decision_cards_insert_failed:${error?.message ?? ""}`);

  await supabase.from("decision_logs").insert({
    tenant_id: tenantId,
    case_id: null,
    agent_id: null,
    input_summary: `Card criado para tensão: ${tensionType}`,
    output_summary: title,
    reasoning_public: "Card de decisão criado automaticamente porque há ações recomendadas executáveis.",
    why_json: {
      kind: "financial_decision_card",
      tension_event_id: tensionEventId,
      tension_type: tensionType,
      severity,
      recommended_actions: actions,
      due_date: dueDate,
    },
    confidence_json: { overall: 0.8, method: "rules" },
    occurred_at: new Date().toISOString(),
  });

  return { ok: true, cardId: created.id };
}

async function createTensionEventWithScore(opts: {
  supabase: any;
  tenantId: string;
  tensionType: string;
  referenceId?: string | null;
  description: string;
  scores: { impact: number; urgency: number; cascade: number; final: number };
}) {
  const { supabase, tenantId, tensionType, referenceId, description, scores } = opts;

  // Avoid spamming: only one event per tenant+tension_type in the last 24h.
  const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
  const { data: existing } = await supabase
    .from("tension_events")
    .select("id")
    .eq("tenant_id", tenantId)
    .eq("tension_type", tensionType)
    .gte("detected_at", since)
    .order("detected_at", { ascending: false })
    .limit(1);

  if ((existing ?? []).length) {
    return { ok: true, skipped: true };
  }

  const { data: ev, error: evErr } = await supabase
    .from("tension_events")
    .insert({
      tenant_id: tenantId,
      tension_type: tensionType,
      reference_id: referenceId ?? null,
      description,
      detected_at: new Date().toISOString(),
    })
    .select("id")
    .maybeSingle();
  if (evErr || !ev?.id) throw new Error(`tension_event_insert_failed:${evErr?.message ?? ""}`);

  const { error: sErr } = await supabase.from("tension_scores").insert({
    tension_event_id: ev.id,
    impact_score: scores.impact,
    urgency_score: scores.urgency,
    cascade_score: scores.cascade,
    final_score: scores.final,
  });
  if (sErr) throw new Error(`tension_score_insert_failed:${sErr.message}`);

  // Reuse existing explanation log structure.
  await supabase.from("decision_logs").insert({
    tenant_id: tenantId,
    case_id: null,
    agent_id: null,
    input_summary: `Tensão detectada: ${tensionType}`,
    output_summary: `Score final ${scores.final.toFixed(1)}`,
    reasoning_public: description,
    why_json: {
      kind: "financial_tension",
      tension_type: tensionType,
      reference_id: referenceId ?? null,
      scores,
    },
    confidence_json: { overall: 0.8, method: "rules" },
    occurred_at: new Date().toISOString(),
  });

  // Create a decision card ONLY if actionable.
  try {
    await ensureDecisionCardFromTension({
      supabase,
      tenantId,
      tensionEventId: ev.id,
      tensionType,
      description,
      severity: "medium",
      referenceId: referenceId ?? null,
    });
  } catch (e) {
    console.warn(`[financial_decision_engine] failed to create decision card (ignored)`, { tenantId, e: String(e) });
  }

  return { ok: true, eventId: ev.id };
}

async function runFinancialTensionChecks(opts: { supabase: any; tenantId: string }) {
  const { supabase, tenantId } = opts;

  // Gather needed aggregates
  const { data: cash } = await supabase.rpc("financial_cash_projection", { p_tenant_id: tenantId });
  const current = Number(cash?.current_balance ?? 0);
  const projected = Number(cash?.projected_balance ?? current);
  const receivablesPending = Number(cash?.receivables_pending ?? 0);
  const payablesPending = Number(cash?.payables_pending ?? 0);

  // 1) risco de caixa negativo (impacto real: projected < 0)
  if (projected < 0) {
    const rule = (await getTenantTensionRule(supabase, tenantId, "cash_negative")) ?? {
      threshold: 0,
      severity: "high",
    };

    const deficit = Math.abs(projected);
    if (deficit > Number(rule.threshold ?? 0)) {
      const impact = clamp((deficit / Math.max(1, Math.abs(current) + 1)) * 100, 25, 100);
      const urgency = clamp(payablesPending > 0 ? 85 : 70, 0, 100);
      const cascade = clamp(60 + Math.min(20, deficit / 1000), 0, 100);
      const scores = computeScores({ impact, urgency, cascade });

      const description = [
        `Risco de caixa negativo (projeção < 0).`,
        `Saldo atual: ${current.toFixed(2)}`,
        `Recebíveis pendentes: ${receivablesPending.toFixed(2)}`,
        `Pagáveis pendentes: ${payablesPending.toFixed(2)}`,
        `Saldo projetado: ${projected.toFixed(2)} (déficit ${deficit.toFixed(2)})`,
      ].join("\n");

      await createTensionEventWithScore({
        supabase,
        tenantId,
        tensionType: "cash_negative",
        referenceId: null,
        description,
        scores,
      });
    }
  }

  // 2) runway baixo (impacto real: projected < threshold)
  // Simple MVP: runway threshold is absolute projected balance.
  {
    const rule = (await getTenantTensionRule(supabase, tenantId, "runway_low")) ?? {
      threshold: 1000,
      severity: "medium",
    };

    const thr = Number(rule.threshold ?? 0);
    if (thr > 0 && projected >= 0 && projected < thr) {
      const gap = thr - projected;
      const impact = clamp((gap / thr) * 100, 15, 90);
      const urgency = clamp(projected < thr * 0.25 ? 80 : 60, 0, 100);
      const cascade = clamp(45 + Math.min(25, gap / 1000), 0, 100);
      const scores = computeScores({ impact, urgency, cascade });

      const description = [
        `Runway baixo: saldo projetado abaixo do limite configurado.`,
        `Saldo projetado: ${projected.toFixed(2)}`,
        `Limite (threshold): ${thr.toFixed(2)}`,
        `Gap: ${gap.toFixed(2)}`,
      ].join("\n");

      await createTensionEventWithScore({
        supabase,
        tenantId,
        tensionType: "runway_low",
        referenceId: null,
        description,
        scores,
      });
    }
  }

  // 3) receita não recebida (impacto real: receivables overdue)
  {
    const { data: overdue, error } = await supabase
      .from("financial_receivables")
      .select("id,amount,due_date,description")
      .eq("tenant_id", tenantId)
      .eq("status", "overdue")
      .order("due_date", { ascending: true })
      .limit(50);

    if (!error && (overdue ?? []).length) {
      const total = (overdue ?? []).reduce((s: number, r: any) => s + Number(r.amount ?? 0), 0);
      if (total > 0) {
        const rule = (await getTenantTensionRule(supabase, tenantId, "revenue_not_received")) ?? {
          threshold: 0,
          severity: "high",
        };
        if (total > Number(rule.threshold ?? 0)) {
          const oldest = overdue![0];
          const impact = clamp(Math.min(100, (total / Math.max(1, receivablesPending + 1)) * 100), 20, 100);
          const urgency = 85;
          const cascade = clamp(50 + Math.min(30, total / 1000), 0, 100);
          const scores = computeScores({ impact, urgency, cascade });

          const sample = overdue!
            .slice(0, 5)
            .map((r: any) => `- ${r.due_date}: ${Number(r.amount ?? 0).toFixed(2)} • ${String(r.description ?? "").slice(0, 60)}`)
            .join("\n");

          const description = [
            `Receita não recebida: há recebíveis em atraso.`,
            `Total em atraso: ${total.toFixed(2)} • Itens: ${overdue!.length}`,
            `Mais antigo: ${oldest.due_date}`,
            sample ? `Exemplos:\n${sample}` : "",
          ]
            .filter(Boolean)
            .join("\n");

          await createTensionEventWithScore({
            supabase,
            tenantId,
            tensionType: "revenue_not_received",
            referenceId: oldest.id,
            description,
            scores,
          });
        }
      }
    }
  }

  // 4) desvio relevante do orçamento (impacto real: actual > expected * threshold)
  {
    // Consider only last 30 days for MVP
    const sinceDate = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

    // Pull budgets
    const { data: budgets, error: bErr } = await supabase
      .from("financial_budgets")
      .select("id,category_id,expected_amount,recurrence,scenario")
      .eq("tenant_id", tenantId)
      .limit(200);

    if (!bErr && (budgets ?? []).length) {
      // Pull transactions with category in last 30 days
      const { data: txs, error: tErr } = await supabase
        .from("financial_transactions")
        .select("id,category_id,amount,type,transaction_date")
        .eq("tenant_id", tenantId)
        .gte("transaction_date", sinceDate)
        .not("category_id", "is", null)
        .limit(5000);

      if (!tErr && (txs ?? []).length) {
        const actualByCat = new Map<string, number>();
        for (const t of txs ?? []) {
          const cat = (t as any).category_id as string | null;
          if (!cat) continue;
          const amt = Number((t as any).amount ?? 0);
          const sign = (t as any).type === "debit" ? 1 : -1; // expenses positive
          actualByCat.set(cat, (actualByCat.get(cat) ?? 0) + amt * sign);
        }

        const rule = (await getTenantTensionRule(supabase, tenantId, "budget_deviation")) ?? {
          threshold: 0.25,
          severity: "medium",
        };

        const ratioThr = Number(rule.threshold ?? 0.25);

        // Find worst deviation with impact
        let worst: { categoryId: string; expected: number; actual: number; deviation: number } | null = null;

        for (const b of budgets ?? []) {
          const catId = (b as any).category_id as string;
          const expected = Number((b as any).expected_amount ?? 0);
          if (expected <= 0) continue;
          const actual = actualByCat.get(catId) ?? 0;

          // only consider overspend (actual > expected)
          if (actual <= expected) continue;

          const deviation = (actual - expected) / expected;
          if (deviation < ratioThr) continue;

          if (!worst || deviation > worst.deviation) worst = { categoryId: catId, expected, actual, deviation };
        }

        if (worst) {
          const excess = worst.actual - worst.expected;
          if (excess > 0) {
            const impact = clamp(Math.min(100, worst.deviation * 100), 20, 100);
            const urgency = clamp(worst.deviation > 0.75 ? 80 : 60, 0, 100);
            const cascade = clamp(40 + Math.min(30, excess / 1000), 0, 100);
            const scores = computeScores({ impact, urgency, cascade });

            const description = [
              `Desvio relevante do orçamento (últimos 30 dias).`,
              `Categoria: ${worst.categoryId}`,
              `Esperado: ${worst.expected.toFixed(2)}`,
              `Real: ${worst.actual.toFixed(2)}`,
              `Excesso: ${excess.toFixed(2)} • Desvio: ${(worst.deviation * 100).toFixed(1)}%`,
              `Threshold: ${(ratioThr * 100).toFixed(1)}%`,
            ].join("\n");

            await createTensionEventWithScore({
              supabase,
              tenantId,
              tensionType: "budget_deviation",
              referenceId: null,
              description,
              scores,
            });
          }
        }
      }
    }
  }

  return { ok: true };
}

function addDaysIsoDate(dateIso: string, days: number) {
  const d = new Date(`${dateIso}T00:00:00Z`);
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}

async function processGuardiaoInsightsGenerateJob(opts: { supabase: any, tenantId: string, journeyId: string, model: string, lookbackDays: number }) {
  const { supabase, tenantId, journeyId, model, lookbackDays } = opts;

  // Calculate the since date
  const sinceDate = new Date(Date.now() - lookbackDays * 24 * 60 * 60 * 1000).toISOString();

  let contextText = "";
  let totalEventsCount = 0;

  if (journeyId === "GLOBAL") {
    // Fetch bank accounts and financial categories for mapping in memory
    const { data: bankAccounts } = await supabase
      .from("bank_accounts")
      .select("id, bank_name, account_name")
      .eq("tenant_id", tenantId);

    const { data: financialCategories } = await supabase
      .from("financial_categories")
      .select("id, name")
      .eq("tenant_id", tenantId);

    const accountMap = new Map((bankAccounts || []).map((a: any) => [a.id, `${a.bank_name} (${a.account_name})`]));
    const categoryMap = new Map((financialCategories || []).map((c: any) => [c.id, c.name]));

    // Global context: Finance and Tasks
    const { data: finances } = await supabase
      .from("financial_transactions")
      .select("type, amount, description, transaction_date, status, source, created_at, account_id, category_id")
      .eq("tenant_id", tenantId)
      .gte("transaction_date", sinceDate.slice(0, 10))
      .order("transaction_date", { ascending: false });

    // Fetch users_profile to resolve assignments safely in memory
    const { data: profiles } = await supabase
      .from("users_profile")
      .select("user_id, display_name")
      .eq("tenant_id", tenantId);

    const profileMap = new Map((profiles || []).map((p: any) => [p.user_id, p.display_name]));

    // Query 1: Journey Tasks
    const { data: journeyTasks } = await supabase
      .from("tasks")
      .select("title, status, created_at, assigned_to_user_id")
      .eq("tenant_id", tenantId)
      .gte("created_at", sinceDate)
      .order("created_at", { ascending: false });

    // Query 2: Super Tasks (Checklists)
    const { data: superTasks } = await supabase
      .from("super_tasks")
      .select("title, is_completed, created_at, assigned_to")
      .eq("tenant_id", tenantId)
      .gte("created_at", sinceDate)
      .order("created_at", { ascending: false });

    const fList = (finances || []);
    const jtList = (journeyTasks || []);
    const stList = (superTasks || []);
    totalEventsCount = fList.length + jtList.length + stList.length;

    if (totalEventsCount === 0) return;

    contextText += `\n--- TRANSAÇÕES FINANCEIRAS RECENTES ---\n`;
    contextText += fList.map((f: any) => {
      const bank = accountMap.get(f.account_id) || 'Desconhecido';
      const cat = categoryMap.get(f.category_id) || 'Sem categoria';
      const createdStr = new Date(f.created_at).toLocaleString('pt-BR');
      return `[${f.transaction_date}] ${f.type.toUpperCase()}: R$ ${f.amount} - ${f.description} (Cat: ${cat} | Banco: ${bank} | Status: ${f.status} | Inserido em: ${createdStr} via ${f.source})`;
    }).join("\n");

    contextText += `\n\n--- TAREFAS DE JORNADAS (PROCESSOS) ---\n`;
    contextText += jtList.map((t: any) => `[${t.created_at.slice(0, 10)}] ${t.title} - Status: ${t.status === 'done' ? 'Concluída' : 'Pendente'} (Atribuído a: ${profileMap.get(t.assigned_to_user_id) || 'Não atribuído'})`).join("\n");

    contextText += `\n\n--- CHECKLISTS GLOBAIS (SUPER-TAREFAS) ---\n`;
    contextText += stList.map((t: any) => `[${t.created_at.slice(0, 10)}] ${t.title} - Status: ${t.is_completed ? 'Concluída' : 'Pendente'} (Atribuído a: ${profileMap.get(t.assigned_to) || 'Não atribuído'})`).join("\n");

  } else {
    // Journey context: timeline events
    const { data: events } = await supabase
      .from("timeline_events")
      .select("event_type, actor_type, message, occurred_at, cases!inner(journey_id)")
      .eq("tenant_id", tenantId)
      .eq("cases.journey_id", journeyId)
      .gte("occurred_at", sinceDate)
      .order("occurred_at", { ascending: false })
      .limit(300);

    if (!events || events.length === 0) return; // No events to analyze
    totalEventsCount = events.length;
    contextText = events.map((e: any) => `[${e.occurred_at}] ${e.actor_type} - ${e.event_type}: ${e.message}`).join("\n");
  }

  // Fetch the latest insight for this journey to use for comparison
  const { data: previousInsight } = await supabase
    .from("guardiao_insights")
    .select("insights_json, created_at")
    .eq("tenant_id", tenantId)
    .eq("journey_id", journeyId)
    .order("created_at", { ascending: false })
    .limit(1)
    .maybeSingle();

  const previousInsightContext = previousInsight ? `
Relatório Anterior (${previousInsight.created_at}):
${JSON.stringify(previousInsight.insights_json)}
` : "";

  // Fetch active prompt
  let customPrompt = undefined;
  if (journeyId !== "GLOBAL") {
    const { data: activePrompt } = await supabase
      .from("prompt_versions")
      .select("prompt_text")
      .eq("tenant_id", tenantId)
      .eq("journey_id", journeyId)
      .eq("is_active", true)
      .limit(1)
      .maybeSingle();
    customPrompt = activePrompt?.prompt_text;
  }

  const baseInstruction = customPrompt 
    ? customPrompt 
    : (journeyId === "GLOBAL" 
        ? `Você é o Guardião de Negócio. Analise as finanças e tarefas recentes de toda a operação da empresa e retorne insights valiosos sobre a saúde financeira e produtividade.
Faça um breve resumo dos padrões observados (ex: fluxo de caixa, conclusão de tarefas) e um comparativo com o relatório anterior (se existir).` 
        : `Você é o Guardião de Negócio. Analise os eventos recentes desta jornada e retorne insights valiosos baseados nesses eventos.
Faça um breve resumo dos padrões de comportamento observados e um comparativo com o relatório anterior (se existir).`);

  const prompt = `${baseInstruction}

INSTRUÇÃO OBRIGATÓRIA DE SAÍDA:
Retorne APENAS um objeto JSON válido no formato abaixo. Não use marcações markdown como \`\`\`json.
{
  "events_count": ${totalEventsCount},
  "summary": "Breve resumo do que foi analisado e do padrão de comportamento",
  "comparison": "Comparativo em relação ao relatório anterior (ou informe que é o primeiro relatório se não houver)",
  "insights": [
    {"title": "título curto", "description": "descrição", "severity": "info|warn|error"}
  ]
}

${previousInsightContext}

Dados Recentes para Análise:
${contextText}`;

  let content = "{}";
  let tokensUsed = 0;

  // 0. Verifica Limites
  try {
    await checkTenantAILimits(tenantId, supabase);
  } catch (err: any) {
    console.log(`[processGuardiaoInsightsGenerateJob] Skipping: ${err.message}`);
    return;
  }

  if (model === "gemini") {
    const apiKey = Deno.env.get("GEMINI_API_KEY") ?? "";
    if (!apiKey) throw new Error("GEMINI_API_KEY is not set");

    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.7, maxOutputTokens: 1500 }
      }),
    });

    if (!res.ok) {
      const txt = await res.text();
      throw new Error(`Gemini error: ${res.status} ${txt}`);
    }

    const json = await res.json();
    content = json.candidates?.[0]?.content?.parts?.[0]?.text ?? "{}";
    tokensUsed = json.usageMetadata?.totalTokenCount || 1000;

    // Cleanup markdown if Gemini ignores instructions
    content = content.replace(/```json/g, '').replace(/```/g, '').trim();

  } else {
    // Default to OpenAI
    const apiKey = Deno.env.get("OPENAI_API_KEY") ?? "";
    if (!apiKey) throw new Error("OPENAI_API_KEY is not set");

    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [{ role: "user", content: prompt }],
        temperature: 0.7,
        max_tokens: 1500
      }),
    });

    if (!res.ok) {
      const txt = await res.text();
      throw new Error(`OpenAI error: ${res.status} ${txt}`);
    }

    const json = await res.json();
    content = json.choices?.[0]?.message?.content ?? "{}";
    tokensUsed = json.usage?.total_tokens || 1000;
  }

  let insights = {};
  try {
    insights = JSON.parse(content);
    // Ensure we inject the actual event count directly in case the LLM ignored it or counted wrong
    if (typeof insights === "object" && insights !== null) {
      (insights as any).events_count = totalEventsCount;
    }
  } catch (e) {
    throw new Error(`Failed to parse insights JSON from AI: ${content}`);
  }

  if (typeof insights === "object" && insights !== null) {
    const { error: insErr } = await supabase.from("guardiao_insights").insert({
      tenant_id: tenantId,
      journey_id: journeyId === "GLOBAL" ? null : journeyId,
      insights_json: insights,
      created_by: null
    });
    if (insErr) throw insErr;
  }

  // Update usage_counters for the current month
  if (tokensUsed > 0) {
    const desc = journeyId === "GLOBAL" ? "Guardião: Análise Global (Financeiro e Tarefas)" : `Guardião: Insights da Jornada (ID: ${journeyId})`;
    await logAITokenUsage(tenantId, tokensUsed, desc, model, supabase);
  }
}

serve(async (req: any) => {
  const fn = "jobs-processor";
  try {
    if (req.method === "OPTIONS") return new Response(null, { headers: corsHeaders });
    if (req.method !== "POST") return new Response("Method not allowed", { status: 405, headers: corsHeaders });

    const supabase = createSupabaseAdmin();

    const batchSize = 10;
    const body = await req.json().catch(() => ({}));
    const manualCommitmentId = String(body.commitment_id ?? "").trim();
    const manualJobId = String(body.job_id ?? "").trim();

    // Fetch pending jobs base query
    let jobsSelect: any = supabase
      .from("job_queue")
      .select("id, tenant_id, type, payload_json, attempts")
      .eq("status", "pending")
      .is("locked_at", null);

    const debug: any = { manualJobId, jobsFound: -1, lockErrors: [] };

    if (manualCommitmentId) {
      // 1. Ensure a pending job exists for this commitment to be picked up
      const { data: existingJob } = await supabase
        .from("job_queue")
        .select("id")
        .eq("status", "pending")
        .eq("type", "COMMITMENT_ORCHESTRATE")
        .contains("payload_json", { commitment_id: manualCommitmentId })
        .is("locked_at", null)
        .maybeSingle();

      if (!existingJob) {
        const { data: comm } = await supabase
          .from("commercial_commitments")
          .select("tenant_id")
          .eq("id", manualCommitmentId)
          .maybeSingle();

        if (comm) {
          await supabase.from("job_queue").insert({
            tenant_id: comm.tenant_id,
            type: "COMMITMENT_ORCHESTRATE",
            idempotency_key: `MANUAL_ORCHESTRATE:${manualCommitmentId}:${Date.now()}`,
            payload_json: { commitment_id: manualCommitmentId },
            status: "pending",
            run_after: new Date().toISOString()
          });
        }
      }
      // Re-assign the mutated builder!
      jobsSelect = jobsSelect.contains("payload_json", { commitment_id: manualCommitmentId });
    } else if (manualJobId) {
      jobsSelect = jobsSelect
        .eq("id", manualJobId)
        .limit(1); // just process this exact job directly
    } else {
      jobsSelect = jobsSelect
        .lte("run_after", new Date().toISOString())
        .order("created_at", { ascending: true })
        .limit(batchSize);
    }

    const { data: jobs, error: jobsErr } = await jobsSelect;

    if (jobsErr) {
      console.error(`[${fn}] Failed to read jobs`, { jobsErr });
      return new Response("Failed to read jobs", { status: 500, headers: corsHeaders });
    }

    debug.jobsFound = jobs?.length || 0;

    const lockedBy = crypto.randomUUID();

    // Lock jobs
    const locked: JobRow[] = [];
    for (const job of (jobs ?? []) as any[]) {
      const { data: updated, error: lockErr } = await supabase
        .from("job_queue")
        .update({ locked_at: new Date().toISOString(), locked_by: lockedBy })
        .eq("id", job.id)
        .eq("status", "pending")
        .select("id, tenant_id, type, payload_json, attempts")
        .maybeSingle();
      if (updated) locked.push(updated as any);
      else debug.lockErrors.push({ jobId: job.id, lockErr });
    }

    const { data: agents } = await supabase.from("agents").select("id, key");
    const agentIdByKey = new Map<string, string>();
    for (const a of agents ?? []) agentIdByKey.set(a.key, a.id);

    const results: any[] = [];

    for (const job of locked) {
      try {
        const tenantId = job.tenant_id;
        const caseId = job.payload_json?.case_id as string | undefined;

        if (job.type === "COMMITMENT_ORCHESTRATE") {
          const commitmentId = String(job.payload_json?.commitment_id ?? "").trim();
          if (!commitmentId) throw new Error("Missing payload.commitment_id");

          const url = `${Deno.env.get("SUPABASE_URL")}/functions/v1/commitment-orchestrator`;
          const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";
          if (!serviceKey) throw new Error("Missing SUPABASE_SERVICE_ROLE_KEY");

          const res = await fetch(url, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${serviceKey}`,
            },
            body: JSON.stringify({ 
              commitment_id: commitmentId, 
              force: Boolean(manualCommitmentId) 
            }),
          });

          const text = await res.text();
          if (!res.ok) {
            throw new Error(`commitment-orchestrator failed: ${res.status} ${text}`);
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, type: job.type, commitmentId, result: text });
          continue;
        }

        if (job.type === "FINANCIAL_INGESTION") {
          const ingestionJobId = String(job.payload_json?.ingestion_job_id ?? "").trim();
          const bucket = String(job.payload_json?.storage_bucket ?? "").trim();
          const path = String(job.payload_json?.storage_path ?? "").trim();

          if (!ingestionJobId || !bucket || !path) throw new Error("Missing payload (ingestion_job_id/storage_bucket/storage_path)");

          const out = await processFinancialIngestionJob({ supabase, tenantId, ingestionJobId, bucket, path });

          // After persisting transactions, run simple financial tension checks.
          try {
            await runFinancialTensionChecks({ supabase, tenantId });
          } catch (e) {
            console.warn(`[${fn}] tension checks failed (ignored)`, { tenantId, e: String(e) });
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, type: job.type, result: out });
          continue;
        }

        if (job.type === "META_PUBLISH_PUBLICATION") {
          const publicationId = String(job.payload_json?.publication_id ?? "").trim();
          if (!publicationId) throw new Error("Missing payload.publication_id");

          const out = await publishContentPublication({ supabase, tenantId, publicationId, requestedByUserId: null });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, type: job.type, publicationId, result: out });
          continue;
        }

        if (job.type === "META_COLLECT_METRICS") {
          const publicationId = String(job.payload_json?.publication_id ?? "").trim();
          const windowDays = Number(job.payload_json?.window_days ?? 1);
          if (!publicationId) throw new Error("Missing payload.publication_id");
          if (![1, 3, 7].includes(windowDays)) throw new Error("Missing/invalid payload.window_days (1|3|7)");

          const out = await collectContentMetricsSnapshot({
            supabase,
            tenantId,
            publicationId,
            windowDays: windowDays as 1 | 3 | 7,
          });

          // Generate a report from all snapshots available
          if (out.ok) {
            const { data: snaps } = await supabase
              .from("content_metrics_snapshots")
              .select("window_days,impressions,profile_visits,follows,messages")
              .eq("tenant_id", tenantId)
              .eq("publication_id", publicationId)
              .order("window_days", { ascending: true })
              .limit(10);

            const points = (snaps ?? []).map((s: any) => ({
              window_days: Number(s.window_days),
              impressions: s.impressions ?? null,
              profile_visits: s.profile_visits ?? null,
              follows: s.follows ?? null,
              messages: s.messages ?? null,
            }));

            const report = buildPerformanceReport({ points, channel: out.publication.channel });
            const agentId = agentIdByKey.get("performance_analyst_agent") ?? null;

            if (agentId) {
              await supabase.from("decision_logs").insert({
                tenant_id: tenantId,
                case_id: out.publication.case_id,
                agent_id: agentId,
                input_summary: `Métricas D+${windowDays} (publicação ${publicationId.slice(0, 8)}…)`,
                output_summary: `Relatório do guardião (D+${windowDays})`,
                reasoning_public: report.reportText,
                why_json: {
                  kind: "content_performance_report",
                  publication_id: publicationId,
                  channel: out.publication.channel,
                  points,
                  derived: report.derived,
                },
                confidence_json: { overall: 0.72, method: "heuristic" },
                occurred_at: new Date().toISOString(),
              });
            }
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: out.ok, type: job.type, publicationId, windowDays, result: out });
          continue;
        }

        if (job.type === "DAILY_WA_SUMMARY") {
          const dateStr = String(job.payload_json?.date ?? "").trim();
          const timeZone = String(job.payload_json?.time_zone ?? "America/Sao_Paulo").trim() || "America/Sao_Paulo";
          if (!/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) throw new Error("Missing/invalid payload.date (YYYY-MM-DD)");

          const next = addDays(dateStr, 1);
          const startIso = new Date(localMidnightUtcMs(dateStr, timeZone)).toISOString();
          const endIso = new Date(localMidnightUtcMs(next, timeZone)).toISOString();

          // Pull messages in pages (MVP)
          const pageSize = 1000;
          const maxPages = 20;
          let all: any[] = [];
          for (let page = 0; page < maxPages; page++) {
            const from = page * pageSize;
            const to = from + pageSize - 1;

            const { data, error } = await supabase
              .from("wa_messages")
              .select("case_id,direction,body_text,occurred_at")
              .eq("tenant_id", tenantId)
              .gte("occurred_at", startIso)
              .lt("occurred_at", endIso)
              .not("case_id", "is", null)
              .order("occurred_at", { ascending: true })
              .range(from, to);

            if (error) throw error;
            if (!data?.length) break;
            all = all.concat(data as any[]);
            if (data.length < pageSize) break;
          }

          if (!all.length) {
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, note: "no messages" });
            continue;
          }

          const { data: existingSummaries } = await supabase
            .from("timeline_events")
            .select("case_id")
            .eq("tenant_id", tenantId)
            .eq("event_type", "daily_conversation_summary")
            .contains("meta_json", { date: dateStr })
            .limit(5000);

          const already = new Set<string>((existingSummaries ?? []).map((r: any) => String(r.case_id)));

          const byCase = new Map<
            string,
            {
              inbound: number;
              outbound: number;
              first: string;
              last: string;
              text: string;
            }
          >();

          for (const m of all) {
            const cid = String((m as any).case_id);
            if (!cid) continue;

            const cur = byCase.get(cid) ?? {
              inbound: 0,
              outbound: 0,
              first: String((m as any).occurred_at),
              last: String((m as any).occurred_at),
              text: "",
            };

            const dir = String((m as any).direction);
            if (dir === "inbound") cur.inbound += 1;
            if (dir === "outbound") cur.outbound += 1;

            const t = String((m as any).occurred_at);
            if (t < cur.first) cur.first = t;
            if (t > cur.last) cur.last = t;

            const body = (m as any).body_text ? String((m as any).body_text) : "";
            if (body) cur.text += `\n${body}`;

            byCase.set(cid, cur);
          }

          const inserts: any[] = [];
          const [yyyy, mm, dd] = dateStr.split("-");
          const dateBr = `${dd}/${mm}`;

          for (const [cid, s] of byCase.entries()) {
            if (already.has(cid)) continue;
            if ((s.inbound + s.outbound) <= 0) continue;

            const topics = buildDailyTopics(s.text).slice(0, 3);
            const topicsText = topics.length ? topics.join(", ") : "(sem tema dominante)";

            inserts.push({
              tenant_id: tenantId,
              case_id: cid,
              event_type: "daily_conversation_summary",
              actor_type: "system",
              actor_id: null,
              message: `Resumo do dia (${dateBr}): ${s.inbound} mensagens do cliente, ${s.outbound} do time. Principais temas: ${topicsText}.`,
              meta_json: {
                date: dateStr,
                time_zone: timeZone,
                inbound_count: s.inbound,
                outbound_count: s.outbound,
                first_message_at: s.first,
                last_message_at: s.last,
                topics,
              },
              occurred_at: new Date().toISOString(),
            });
          }

          if (inserts.length) {
            await supabase.from("timeline_events").insert(inserts);
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, date: dateStr, inserted: inserts.length, cases: byCase.size });
          continue;
        }

        if (job.type === "BEEIA_PROCESS_MESSAGE") {
          const caseId = job.payload_json?.case_id;
          const tenantId = job.payload_json?.tenant_id;
          const messageId = job.payload_json?.message_id;
          const instanceId = job.payload_json?.instance_id;

          if (!caseId || !tenantId || !messageId || !instanceId) {
            throw new Error(`Missing required fields: caseId=${caseId}, tenantId=${tenantId}, messageId=${messageId}, instanceId=${instanceId}`);
          }

          // 1. Fetch case details and verify it is still open and in 'contato' state
          const { data: c, error: cErr } = await supabase
            .from("cases")
            .select("id, status, state, customer_id, title, beeia_paused")
            .eq("tenant_id", tenantId)
            .eq("id", caseId)
            .maybeSingle();

          if (cErr) throw cErr;
          if (!c) {
            console.log(`[BEEIA_PROCESS_MESSAGE] Case ${caseId} not found, skipping`);
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "case_not_found" });
            continue;
          }

          if (c.status !== "open" || c.state !== "contato") {
            console.log(`[BEEIA_PROCESS_MESSAGE] Case ${caseId} is not in 'open/contato' status/state (status=${c.status}, state=${c.state}), skipping`);
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "case_not_eligible" });
            continue;
          }

          // 1b. Check if BeeIA is manually paused for this case
          if ((c as any).beeia_paused === true) {
            console.log(`[BEEIA_PROCESS_MESSAGE] Case ${caseId} has BeeIA paused by user, skipping`);
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "beeia_paused_by_user" });
            continue;
          }

          // 1c. Fetch case message history early so it can be used for plugs scanning and prompts
          const { data: msgs, error: msgsErr } = await supabase
            .from("wa_messages")
            .select("direction, body_text, type, occurred_at")
            .eq("tenant_id", tenantId)
            .eq("case_id", caseId)
            .order("occurred_at", { ascending: true })
            .limit(15);

          if (msgsErr) throw msgsErr;

          // 2. Fetch BeeIA configs
          const { data: config, error: cfgErr } = await supabase
            .from("beeia_configs")
            .select("system_prompt, target_stage, is_active")
            .eq("tenant_id", tenantId)
            .maybeSingle();

          if (cfgErr) throw cfgErr;

          if (config && config.is_active === false) {
            console.log(`[BEEIA_PROCESS_MESSAGE] BeeIA is globally disabled for tenant ${tenantId}, skipping`);
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "beeia_globally_disabled" });
            continue;
          }

          // Use default settings if none configured yet
          let sysPrompt = config?.system_prompt || 'Você é a BeeIA, assistente virtual de atendimento da empresa. Responda educadamente às dúvidas do cliente sobre nossos produtos e serviços. Caso o cliente queira falar com um atendente humano ou demonstre interesse real em fechar negócio, finalize sua mensagem incluindo a tag [STAGE_TRANSITION] no final da sua resposta.';
          const targetStage = config?.target_stage || 'morno';

          // 2a. Fetch Learnings
          const { data: learnings, error: lrnErr } = await supabase
            .from("beeia_learnings")
            .select("learning_text")
            .eq("tenant_id", tenantId);

          if (!lrnErr && learnings && learnings.length > 0) {
            sysPrompt += "\n\n[REGRAS APRENDIDAS EM TREINAMENTOS ANTERIORES]:\n";
            learnings.forEach((l, i) => {
              sysPrompt += `${i + 1}. ${l.learning_text}\n`;
            });
          }

          // 2b. Fetch active Plugs
          const { data: plugs, error: plugsErr } = await supabase
            .from("beeia_plugs")
            .select("plug_key, is_enabled, config_json")
            .eq("tenant_id", tenantId)
            .eq("is_enabled", true);

          let crmTargetStage = targetStage;
          let crmAssigneeId = null;

          if (!plugsErr && plugs && plugs.length > 0) {
            sysPrompt += "\n\n[INTEGRAÇÕES E RECURSOS DO SISTEMA ATIVOS]:\n";

            // 1. CRM Plugue
            const crmPlug = plugs.find(p => p.plug_key === "crm_journeys");
            if (crmPlug) {
              crmTargetStage = crmPlug.config_json?.target_stage || targetStage;
              crmAssigneeId = crmPlug.config_json?.assigned_user_id || null;
              sysPrompt += `- CRM & Encaminhamento: A IA qualificará os leads interessados e os moverá para a etapa "${crmTargetStage}".\n`;
            }

            // 2. Entidades Catalog Plugue
            const coreEntPlug = plugs.find(p => p.plug_key === "core_entities");
            if (coreEntPlug) {
              const allowedFields = coreEntPlug.config_json?.allowed_fields || [];
              const limitInstructions = coreEntPlug.config_json?.limit_instructions || "";

              // Query Case Items offering linked to this case
              const { data: propItem } = await supabase
                .from("case_items")
                .select("offering_entity_id")
                .eq("case_id", caseId)
                .limit(1)
                .maybeSingle();

              let lastInboundMsg = "";
              if (messageId) {
                const { data: tempMsg } = await supabase
                  .from("wa_messages")
                  .select("body_text")
                  .eq("id", messageId)
                  .maybeSingle();
                lastInboundMsg = tempMsg?.body_text || "";
              }

              let propEntity = null;
              if (propItem?.offering_entity_id) {
                const { data: ent } = await supabase
                  .from("core_entities")
                  .select("*")
                  .eq("id", propItem.offering_entity_id)
                  .maybeSingle();
                propEntity = ent;
              }

              if (!propEntity) {
                let messagesToScan: string[] = [];
                if (lastInboundMsg) messagesToScan.push(lastInboundMsg);
                if (msgs && msgs.length > 0) {
                  const inboundHistory = msgs
                    .filter(m => m.direction === "inbound" && m.body_text)
                    .map(m => m.body_text!);
                  messagesToScan = [...messagesToScan, ...inboundHistory.reverse()];
                }

                for (const msgToScan of messagesToScan) {
                  const words = msgToScan.match(/[a-zA-Z0-9]+/g) || [];
                  const cleanWords = words.map(w => w.replace(/[^a-zA-Z0-9]/g, "")).filter(Boolean);
                  if (cleanWords.length > 0) {
                    const searchTerms = Array.from(new Set([
                      ...cleanWords,
                      ...cleanWords.map(w => w.toUpperCase()),
                      ...cleanWords.map(w => w.toLowerCase())
                    ]));
                    const { data: matchedEnt } = await supabase
                      .from("core_entities")
                      .select("*")
                      .eq("tenant_id", tenantId)
                      .eq("entity_type", "offering")
                      .is("deleted_at", null)
                      .or(`internal_code.in.(${searchTerms.join(",")}),legacy_id.in.(${searchTerms.join(",")})`)
                      .limit(1)
                      .maybeSingle();

                    if (matchedEnt) {
                      propEntity = matchedEnt;

                      // Auto-link property to case_items to persist in the database
                      try {
                        const { data: maxItem } = await supabase
                          .from("case_items")
                          .select("line_no")
                          .eq("case_id", caseId)
                          .order("line_no", { ascending: false })
                          .limit(1)
                          .maybeSingle();
                        const nextLineNo = (maxItem?.line_no || 0) + 1;

                        await supabase
                          .from("case_items")
                          .insert({
                            tenant_id: tenantId,
                            case_id: caseId,
                            offering_entity_id: matchedEnt.id,
                            line_no: nextLineNo,
                            qty: 1,
                            confidence_json: { source: "beeia_detection" }
                          });
                      } catch (errLink) {
                        console.warn("[BEEIA] Failed to link offering to case_items", errLink);
                      }

                      break;
                    }
                  }
                }
              }

              if (propEntity) {
                sysPrompt += `\n[IMÓVEL DE INTERESSE DO CLIENTE]:\n`;
                sysPrompt += `- Código Interno: ${propEntity.internal_code || "Sem código"}\n`;
                if (propEntity.legacy_id) {
                  sysPrompt += `- Código Legado / ID no sistema: ${propEntity.legacy_id}\n`;
                }
                sysPrompt += `- Título/Nome: ${propEntity.display_name}\n`;

                const meta = propEntity.metadata || {};
                if (allowedFields.includes("price")) {
                  const pVal = propEntity.business_type === "rent" ? (meta.price_rent || meta.price_sale || meta.price) : (meta.price_sale || meta.price);
                  const pStr = meta.price_consult || !pVal ? "Sob consulta" : Number(pVal).toLocaleString("pt-BR", { minimumFractionDigits: 2 });
                  sysPrompt += `- Preço: R$ ${pStr} (${propEntity.business_type === "rent" ? "Locação" : "Venda"})\n`;
                }
                if (allowedFields.includes("description") && meta.description) {
                  sysPrompt += `- Descrição Comercial: ${meta.description}\n`;
                }
                if (meta.ad_url) {
                  sysPrompt += `- Link do Anúncio (Mais detalhes): ${meta.ad_url}\n`;
                }
                if (allowedFields.includes("area")) {
                  if (propEntity.total_area) sysPrompt += `- Área Total: ${propEntity.total_area} m²\n`;
                  if (propEntity.useful_area) sysPrompt += `- Área Útil: ${propEntity.useful_area} m²\n`;
                }
                if (allowedFields.includes("rooms")) {
                  if (meta.rooms) sysPrompt += `- Quartos: ${meta.rooms}\n`;
                  if (meta.bathrooms) sysPrompt += `- Banheiros: ${meta.bathrooms}\n`;
                  if (meta.suites) sysPrompt += `- Suítes: ${meta.suites}\n`;
                  if (meta.garage) sysPrompt += `- Vagas: ${meta.garage}\n`;
                }
                if (allowedFields.includes("location") && propEntity.location_json) {
                  const loc = propEntity.location_json;
                  sysPrompt += `- Localização: Bairro ${loc.neighborhood || ""}, ${loc.city || ""}-${loc.state || ""}\n`;
                }
                if (allowedFields.includes("photos")) {
                  const { data: photos } = await supabase
                    .from("core_entity_photos")
                    .select("url, room_type")
                    .eq("entity_id", propEntity.id)
                    .eq("tenant_id", tenantId)
                    .is("deleted_at", null);
                  if (photos && photos.length > 0) {
                    sysPrompt += `- Fotos oficiais para enviar ao cliente:\n`;
                    photos.forEach(ph => {
                      sysPrompt += `  * Foto (${ph.room_type || 'Geral'}): ${ph.url}\n`;
                    });
                  }
                }
              }

              // Load up to 5 other active properties/offerings
              const { data: otherProps } = await supabase
                .from("core_entities")
                .select("id, internal_code, display_name, metadata, business_type")
                .eq("tenant_id", tenantId)
                .eq("entity_type", "offering")
                .eq("status", "active")
                .is("deleted_at", null)
                .neq("id", propEntity?.id || "00000000-0000-0000-0000-000000000000")
                .limit(5);

              if (otherProps && otherProps.length > 0) {
                sysPrompt += `\n[OUTROS IMÓVEIS DISPONÍVEIS NO PORTFÓLIO]:\n`;
                otherProps.forEach(op => {
                  const opMeta = op.metadata || {};
                  const opVal = op.business_type === "rent" ? (opMeta.price_rent || opMeta.price_sale || opMeta.price) : (opMeta.price_sale || opMeta.price);
                  const opStr = opMeta.price_consult || !opVal ? "Sob consulta" : Number(opVal).toLocaleString("pt-BR", { minimumFractionDigits: 2 });
                  sysPrompt += `- Cód: ${op.internal_code || "N/A"} | ${op.display_name} | Preço: R$ ${opStr} | Negócio: ${op.business_type === "rent" ? "Locação" : "Venda"}`;
                  if (opMeta.ad_url) sysPrompt += ` | Link: ${opMeta.ad_url}`;
                  sysPrompt += `\n`;
                });
              }

              if (limitInstructions) {
                sysPrompt += `\n[DIRETRIZES E LIMITES DE INFORMAÇÕES DE IMÓVEIS]:\n${limitInstructions}\n`;
              }

              sysPrompt += `\n[DIRETRIZES IMPORTANTES PARA APRESENTAÇÃO DE IMÓVEIS]:
- Liste APENAS as informações e características que possuem valor preenchido. NUNCA mostre campos vazios ou sem informação (ex: se não tem quartos informados, não escreva "Quartos:").
- Sempre inclua o "Link do Anúncio" no final da apresentação de cada imóvel, se a URL estiver disponível.
- Para enviar fotos, retorne EXATAMENTE no formato Markdown: ![Descrição](URL). O sistema interceptará e enviará a imagem real no WhatsApp.
`;
            }

            // 3. Financeiro & Cobrança Plugue
            const finBillingPlug = plugs.find(p => p.plug_key === "financial_billing");
            if (finBillingPlug) {
              const pixKey = finBillingPlug.config_json?.pix_key || "";
              const allowCheckReceivables = finBillingPlug.config_json?.allow_check_receivables ?? false;
              const billingInstructions = finBillingPlug.config_json?.billing_instructions || "";

              sysPrompt += `\n[INTEGRAÇÃO FINANCEIRA - FATURAS E PAGAMENTOS]:\n`;
              if (pixKey) {
                sysPrompt += `- Chave PIX Oficial para Recebimento: "${pixKey}"\n`;
              }

              if (allowCheckReceivables) {
                // Get customer account entity_id
                const { data: caseWithCust } = await supabase
                  .from("cases")
                  .select("customer_id")
                  .eq("id", caseId)
                  .maybeSingle();

                if (caseWithCust?.customer_id) {
                  const { data: custAcc } = await supabase
                    .from("customer_accounts")
                    .select("entity_id")
                    .eq("id", caseWithCust.customer_id)
                    .maybeSingle();

                  if (custAcc?.entity_id) {
                    // Fetch unpaid receivables
                    const { data: receivables } = await supabase
                      .from("financial_receivables")
                      .select("description, amount, due_date, status")
                      .eq("entity_id", custAcc.entity_id)
                      .neq("status", "paid")
                      .is("deleted_at", null)
                      .order("due_date", { ascending: true });

                    if (receivables && receivables.length > 0) {
                      sysPrompt += `- Faturas/Recebíveis em Aberto do Cliente Atual:\n`;
                      receivables.forEach(r => {
                        const due = r.due_date ? new Date(r.due_date).toLocaleDateString("pt-BR") : "Não definida";
                        sysPrompt += `  * "${r.description || 'Fatura'}" | Valor: R$ ${r.amount} | Vencimento: ${due} | Status: ${r.status}\n`;
                      });
                    } else {
                      sysPrompt += `- O cliente atual NÃO possui faturas em aberto no momento.\n`;
                    }
                  }
                }
              }

              if (billingInstructions) {
                sysPrompt += `- Regras de Faturamento e Cobrança: ${billingInstructions}\n`;
              }
            }

            // 4. Simulador de Financiamento Plugue
            const simPlug = plugs.find(p => p.plug_key === "financing_simulator");
            if (simPlug) {
              const allowUseBankRules = simPlug.config_json?.allow_use_bank_rules ?? false;
              const customInstructions = simPlug.config_json?.custom_instructions || "";

              sysPrompt += `\n[INTEGRAÇÃO - SIMULADOR DE FINANCIAMENTO]:\n`;
              sysPrompt += `- OBRIGATÓRIO: Assim que tiver as informações necessárias (valor do imóvel e valor da entrada), realize o cálculo e entregue o resultado da simulação IMEDIATAMENTE na mesma mensagem. Nunca peça para o cliente aguardar ("um momento", "vou calcular") sem exibir os valores simulados.\n`;
              sysPrompt += `- FORMATO E DIAGRAMAÇÃO: Apresente os resultados de forma extremamente organizada, bonita e legível para o WhatsApp. Use quebras de linha duplas entre os blocos, emojis e marcadores. Estruture assim:
  * Exiba o resumo em tópicos (Valor do Imóvel, Entrada, Valor Financiado).
  * Exiba cada banco/opção como um bloco separado por uma linha em branco.
  * Para cada banco use negrito para destacar as informações fundamentais, por exemplo:
    🏦 **Caixa Econômica Federal (CEF)**
    - **Taxa:** 4,75% a.a.
    - **Prazo:** 420 meses
    - **Parcela Estimada:** R$ 2.305,00
  * Nunca junte tudo em um único parágrafo corrido.\n`;
              if (allowUseBankRules) {
                const { data: bankRules } = await supabase
                  .from("financing_bank_rules")
                  .select("bank_name, bank_code, base_rate_pct, max_term_months, tac_json, min_loan_value, max_loan_value")
                  .eq("tenant_id", tenantId)
                  .eq("is_active", true)
                  .is("deleted_at", null);

                if (bankRules && bankRules.length > 0) {
                  sysPrompt += `Você está integrado ao Simulador de Financiamento Imobiliário oficial. Use os parâmetros reais de taxas por banco:\n`;
                  bankRules.forEach(br => {
                    sysPrompt += `- Banco: ${br.bank_name} (${br.bank_code}) | Taxa anual: ${br.base_rate_pct}% a.a. | Prazo máximo: ${br.max_term_months || 420} meses\n`;
                  });

                  sysPrompt += `\nInstruções de Cálculo de Financiamento:\n`;
                  sysPrompt += `- Valor Financiado = Valor Imóvel - Entrada\n`;
                  sysPrompt += `- SAC (Sistema de Amortização Constante):\n`;
                  sysPrompt += `  * Amortização Mensal = Valor Financiado / Prazo (meses)\n`;
                  sysPrompt += `  * Juros Mensais = Saldo Devedor * (Taxa Anual / 12 / 100)\n`;
                  sysPrompt += `  * Seguro Estimado = (Saldo Devedor / 1000) * 0.28\n`;
                  sysPrompt += `  * Parcela Mensal = Amortização + Juros + Seguro\n`;
                  sysPrompt += `- PRICE (Parcelas Fixas): Calcule parcelas fixas brutas padrão de financiamento mensal usando fórmula PRICE padrão adicionando o seguro estimado.\n`;
                }
              }

              if (customInstructions) {
                sysPrompt += `- Regras de Financiamento: ${customInstructions}\n`;
              }
            }
          }

          // 5. Discord Notifications Plugue
          const discordPlug = plugs.find(p => p.plug_key === "discord_notifications");
          if (discordPlug) {
            const trigger = discordPlug.config_json?.trigger_instructions || "";
            const tmpl = discordPlug.config_json?.notification_template || "";
            if (trigger && tmpl) {
              sysPrompt += `\n[INTEGRAÇÃO - NOTIFICAÇÃO DISCORD]:\n`;
              sysPrompt += `- REGRA DE DISPARO: ${trigger}\n`;
              sysPrompt += `- AÇÃO EXIGIDA: Quando a regra acima for atingida, você OBRIGATORIAMENTE deve incluir no final da sua resposta a notificação envolvida nas tags XML <DISCORD_NOTIFY> e </DISCORD_NOTIFY>. Preserve as quebras de linha exatas do template!\n`;
              sysPrompt += `- FORMATO DO TEXTO (substitua as variaveis pelos dados reais da conversa):\n<DISCORD_NOTIFY>\n${tmpl}\n</DISCORD_NOTIFY>\n`;
            }
          }

          // 6. Consulting Schedule Plugue
          const consultingPlug = plugs.find(p => p.plug_key === "consulting_schedule");
          if (consultingPlug) {
            const schedulingRules = consultingPlug.config_json?.scheduling_rules || "";
            if (schedulingRules) {
              sysPrompt += `\n[INTEGRAÇÃO - AGENDA DE CONSULTORIA]:\n`;
              sysPrompt += `- REGRAS DE AGENDAMENTO (disponibilidade, horários, dias da semana, duração): ${schedulingRules}\n`;

              // Buscar compromissos futuros
              const { data: scheduledEvents } = await supabase
                .from("timeline_events")
                .select("meta_json")
                .eq("tenant_id", tenantId)
                .eq("event_type", "consulting_scheduled")
                .gte("occurred_at", new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString());

              if (scheduledEvents && scheduledEvents.length > 0) {
                const bookedTimes = scheduledEvents
                  .map(e => e.meta_json?.scheduled_for)
                  .filter(Boolean)
                  .join(", ");
                if (bookedTimes) {
                  sysPrompt += `- HORÁRIOS JÁ OCUPADOS (INDISPONÍVEIS): ${bookedTimes}\n`;
                }
              } else {
                sysPrompt += `- HORÁRIOS JÁ OCUPADOS (INDISPONÍVEIS): Nenhum.\n`;
              }

              sysPrompt += `- AÇÃO EXIGIDA: Sugira horários livres baseando-se nas REGRAS DE AGENDAMENTO e evite rigorosamente os HORÁRIOS JÁ OCUPADOS. Quando o cliente confirmar o horário escolhido, VOCÊ DEVE OBRIGATORIAMENTE incluir no final da sua resposta a tag exata: [AGENDAR_CONSULTORIA: YYYY-MM-DD HH:MM] substituindo pelo dia e hora escolhidos.\n`;
            }
          }

          // 3. Fetch wa_instance to verify beeia_enabled is true
          const { data: inst, error: instErr } = await supabase
            .from("wa_instances")
            .select("id, beeia_enabled, zapi_instance_id, phone_number")
            .eq("tenant_id", tenantId)
            .eq("id", instanceId)
            .maybeSingle();

          if (instErr) throw instErr;
          if (!inst || !inst.beeia_enabled) {
            console.log(`[BEEIA_PROCESS_MESSAGE] Instance ${instanceId} not found or has BeeIA disabled, skipping`);
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "beeia_disabled_on_instance" });
            continue;
          }

          // 4. Load the specific inbound message to get the sender's phone number and timestamp
          const { data: inMsg, error: inMsgErr } = await supabase
            .from("wa_messages")
            .select("from_phone, occurred_at")
            .eq("id", messageId)
            .maybeSingle();

          if (inMsgErr) throw inMsgErr;
          const customerPhone = inMsg?.from_phone;
          if (!customerPhone) {
            throw new Error(`Inbound message ${messageId} does not have a from_phone`);
          }

          let customerName = "Não informado";
          const { data: contact } = await supabase
            .from("wa_contacts")
            .select("name")
            .eq("tenant_id", tenantId)
            .eq("phone_number", customerPhone)
            .maybeSingle();
          if (contact && contact.name) {
            customerName = contact.name;
          }

          sysPrompt += `\n[DADOS DO LEAD ATUAL]\n- Telefone: ${customerPhone}\n- Nome: ${customerName}\n`;

          // 4b. Deduplication guard: if BeeIA already processed a job or sent an outbound
          // message for this case AFTER the triggering message, skip. This prevents
          // duplicate AI responses when multiple inbound messages arrive in rapid succession.
          if (inMsg?.occurred_at && !job.payload_json?.manual_retake) {
            // Check if another BEEIA job was already completed for this case after this message
            const { data: laterDoneJob } = await supabase
              .from("job_queue")
              .select("id")
              .eq("tenant_id", tenantId)
              .eq("type", "BEEIA_PROCESS_MESSAGE")
              .eq("status", "done")
              .contains("payload_json", { case_id: caseId })
              .gt("updated_at", inMsg.occurred_at)
              .neq("id", job.id)
              .limit(1)
              .maybeSingle();

            if (laterDoneJob) {
              console.log(`[BEEIA_PROCESS_MESSAGE] Another BEEIA job already completed after message ${messageId}, skipping duplicate`);
              await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
              results.push({ id: job.id, ok: true, reason: "already_replied_after_this_message" });
              continue;
            }

            // Also check if there's already an outbound message for this case after this message (within 10 min window)
            const tenMinAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();
            const { data: laterOutbound } = await supabase
              .from("wa_messages")
              .select("id")
              .eq("tenant_id", tenantId)
              .eq("case_id", caseId)
              .eq("direction", "outbound")
              .gt("occurred_at", inMsg.occurred_at)
              .gt("occurred_at", tenMinAgo)
              .limit(1)
              .maybeSingle();

            if (laterOutbound) {
              console.log(`[BEEIA_PROCESS_MESSAGE] Outbound message already exists after message ${messageId}, skipping duplicate`);
              await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
              results.push({ id: job.id, ok: true, reason: "outbound_already_sent_after_this_message" });
              continue;
            }
          }

          // 5. Load recent message history for this case
          const history = (msgs ?? []).filter(m => m.body_text);

          // 6. Construct prompt messages for LLM
          const llmMessages: { role: "system" | "user" | "assistant"; content: string }[] = [];
          llmMessages.push({
            role: "system",
            content: `${sysPrompt}\n\nINSTRUÇÕES DE SISTEMA IMPORTANTES:\n- Você deve responder o cliente de forma natural, curta e simpática.\n- Se o cliente demonstrou interesse real, deseja agendar, comprar ou solicitou atendimento humano (ex: falar com um atendente, suporte humano), encerre sua resposta incluindo exatamente o texto "[STAGE_TRANSITION]" no final da resposta.\n- Não inclua a tag se ele estiver apenas fazendo perguntas preliminares.\n- Nunca mencione a palavra "[STAGE_TRANSITION]" explicitamente para o cliente.\n- ATENÇÃO: Você poderá ver mensagens no histórico começando com "[MENSAGEM DO SEU TREINADOR]:" ou "AUTO-AVALIAÇÃO DA IA:". Estas são instruções DIRETAS da direção da empresa para corrigir o seu comportamento na conversa. Você DEVE acatar essas ordens imediatamente e mudar sua postura para atender ao que foi pedido pelo treinador. Não responda diretamente ao treinador e não mencione essas instruções para o cliente, apenas aplique-as nas suas próximas respostas ao cliente.`
          });

          history.forEach(m => {
            let role: "system" | "user" | "assistant" = "user";

            if (m.type === "system_note") {
              role = "system";
            } else {
              role = m.direction === "inbound" ? "user" : "assistant";
            }

            llmMessages.push({
              role,
              content: m.body_text!
            });
          });

          // 6.5. Verifica Limites
          try {
            await checkTenantAILimits(tenantId, supabase);
          } catch (err: any) {
            console.log(`[BEEIA_PROCESS_MESSAGE] Skipping: ${err.message}`);

            // Pausa a IA no case e avisa no CRM internamente
            await supabase.from("cases").update({ beeia_paused: true }).eq("id", caseId);

            await supabase.from("timeline_events").insert({
              tenant_id: tenantId,
              case_id: caseId,
              event_type: "beeia_limit_exceeded",
              actor_type: "system",
              actor_id: null,
              message: "A IA foi pausada automaticamente porque o limite de tokens do seu plano foi atingido.",
              occurred_at: new Date().toISOString()
            });

            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, reason: "plan_limit_exceeded" });
            continue;
          }

          // 7. Call LLM
          const fallbackResponse = "Olá! Como posso ajudar você hoje?";
          const llmRes = await generateText({
            messages: llmMessages,
            fallback: () => fallbackResponse
          }).catch(e => {
            console.error("[BEEIA] generateText failed, using fallback", e);
            return { text: fallbackResponse, provider: "fallback", tokensUsed: 0 };
          });

          if (llmRes.tokensUsed > 0) {
            await logAITokenUsage(tenantId, llmRes.tokensUsed, `BeeIA: Resposta para ${customerPhone}`, llmRes.provider, supabase, "case", caseId);
          }

          let responseText = llmRes.text.trim();

          // Check for Discord Notifications
          const discordMatch = responseText.match(/<DISCORD_NOTIFY>([\s\S]*?)<\/DISCORD_NOTIFY>/i);
          if (discordMatch && discordMatch[1]) {
            const discordText = discordMatch[1].trim();
            responseText = responseText.replace(/<DISCORD_NOTIFY>[\s\S]*?<\/DISCORD_NOTIFY>/gi, "").trim();

            const dp = plugs.find(p => p.plug_key === "discord_notifications");
            const webhookUrl = dp?.config_json?.webhook_url;
            if (webhookUrl) {
              fetch(webhookUrl, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  content: discordText.replace(/\\n/g, '\n'),
                  username: "BeeIA Notificações",
                  avatar_url: "https://github.com/marcelahubpaladio.png"
                })
              }).catch(err => console.error("[BEEIA] Failed to send Discord notification", err));
            }
          }

          const shouldTransition = responseText.includes("[STAGE_TRANSITION]");

          if (shouldTransition) {
            // Clean tag
            responseText = responseText.replace(/\[STAGE_TRANSITION\]/gi, "").trim();

             // Update Case State & add timeline event
            const caseUpdatePayload: any = { state: crmTargetStage, updated_at: new Date().toISOString() };
            if (crmAssigneeId) {
              caseUpdatePayload.assigned_user_id = crmAssigneeId;
            }

            const { error: updateErr } = await supabase
              .from("cases")
              .update(caseUpdatePayload)
              .eq("id", caseId);

            if (updateErr) {
              console.error("[BEEIA] Failed to update case state to target_stage", updateErr);
            } else {
              let transitionMsg = `Lead qualificado pela BeeIA e movido para a etapa: ${crmTargetStage}`;
              if (crmAssigneeId) {
                const { data: userProf } = await supabase
                  .from("users_profile")
                  .select("display_name")
                  .eq("user_id", crmAssigneeId)
                  .maybeSingle();
                if (userProf?.display_name) {
                  transitionMsg += ` (atribuído para ${userProf.display_name})`;
                }
              }

              await supabase.from("timeline_events").insert({
                tenant_id: tenantId,
                case_id: caseId,
                event_type: "journey_transition",
                actor_type: "ai",
                message: transitionMsg,
                occurred_at: new Date().toISOString()
              });
            }
          }

          // Check for Consulting Schedule Booking
          const scheduleMatch = responseText.match(/\[AGENDAR_CONSULTORIA:\s*(.+?)\]/i);
          if (scheduleMatch && scheduleMatch[1]) {
            const scheduledDateTime = scheduleMatch[1].trim();
            responseText = responseText.replace(/\[AGENDAR_CONSULTORIA:[\s\S]*?\]/gi, "").trim();

            await supabase.from("timeline_events").insert({
              tenant_id: tenantId,
              case_id: caseId,
              event_type: "consulting_scheduled",
              actor_type: "ai",
              message: `Consultoria agendada pela BeeIA para: ${scheduledDateTime}`,
              meta_json: { scheduled_for: scheduledDateTime },
              occurred_at: new Date().toISOString()
            });
          }

          // 8. Send reply via integrations-zapi-send Edge Function
          const supabaseUrl = Deno.env.get("SUPABASE_URL")?.replace(/\/$/, "");
          const functionUrl = supabaseUrl ? `${supabaseUrl}/functions/v1` : "http://localhost:54321/functions/v1";
          const sendUrl = `${functionUrl}/integrations-zapi-send`;
          const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";

          console.log(`[BEEIA] Dispatching response to integrations-zapi-send: ${sendUrl}`);

          // Parse markdown images and split into multiple messages if needed
          const msgParts: Array<{ type: string; content?: string; caption?: string; mediaUrl?: string }> = [];
          const mdImgRegex = /!\[([^\]]*)\]\(([^)]+)\)/g;
          let lastIdx = 0;
          let mdMatch;

          while ((mdMatch = mdImgRegex.exec(responseText)) !== null) {
            const textBefore = responseText.substring(lastIdx, mdMatch.index).trim();
            if (textBefore) {
              msgParts.push({ type: "text", content: textBefore });
            }
            msgParts.push({ type: "image", caption: mdMatch[1], mediaUrl: mdMatch[2] });
            lastIdx = mdImgRegex.lastIndex;
          }

          const textAfter = responseText.substring(lastIdx).trim();
          if (textAfter) {
            msgParts.push({ type: "text", content: textAfter });
          }

          if (msgParts.length === 0) {
             msgParts.push({ type: "text", content: responseText });
          }

          let anyError = false;
          let delayMs = 0;

          for (const part of msgParts) {
            if (delayMs > 0) {
               await new Promise(resolve => setTimeout(resolve, delayMs));
            }

            const payload: any = {
              tenantId,
              instanceId,
              to: customerPhone,
              type: part.type,
              correlationId: `BEEIA_REPLY:${caseId}:${Date.now()}`
            };

            if (part.type === "text") {
              payload.text = part.content;
            } else if (part.type === "image") {
              payload.mediaUrl = part.mediaUrl;
              payload.text = ""; // ZAPI uses caption, integrations-zapi-send maps text -> caption if type=image
            }

            const sendRes = await fetch(sendUrl, {
              method: "POST",
              headers: {
                "Content-Type": "application/json",
                Authorization: `Bearer ${serviceRoleKey}`
              },
              body: JSON.stringify(payload)
            }).catch(err => {
              console.error("[BEEIA] fetch integrations-zapi-send failed", err);
              return null;
            });

            if (sendRes && !sendRes.ok) {
              const errTxt = await sendRes.text().catch(() => "");
              console.error(`[BEEIA] integrations-zapi-send failed with status ${sendRes.status}: ${errTxt}`);
              anyError = true;
            }

            delayMs = 1500; // delay between messages to keep order in whatsapp
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: !anyError, transitioned: shouldTransition });
          continue;
        }

        if (job.type === "COMMITMENT_ORCHESTRATE") {
          const commitmentId = job.payload_json?.commitment_id;
          if (!commitmentId) throw new Error("Missing commitment_id");

          const { data: items } = await supabase
            .from("commitment_items")
            .select("id, offering_entity_id, quantity")
            .eq("commitment_id", commitmentId)
            .eq("requires_fulfillment", true);

          const deliverablesToInsert: any[] = [];

          for (const item of (items || [])) {
            const { data: templates } = await supabase
              .from("deliverable_templates")
              .select("id, name, quantity, estimated_minutes, required_resource_type")
              .eq("offering_entity_id", item.offering_entity_id)
              .is("deleted_at", null);

            for (const t of (templates || [])) {
              const baseQty = Number(t.quantity ?? 1);
              const itemMultiplier = Number(item.quantity ?? 1);
              const totalToCreate = baseQty * itemMultiplier;

              for (let i = 0; i < totalToCreate; i++) {
                deliverablesToInsert.push({
                  tenant_id: tenantId,
                  commitment_id: commitmentId,
                  entity_id: item.offering_entity_id,
                  template_id: t.id,
                  name: t.name,
                  status: 'pending'
                });
              }
            }
          }

          if (deliverablesToInsert.length > 0) {
            const { error: insErr } = await supabase.from("deliverables").insert(deliverablesToInsert);
            if (insErr) throw insErr;
          }

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, count: deliverablesToInsert.length });
          continue;
        }

        if (job.type === "GUARDIAO_INSIGHTS_GENERATE") {
          const journeyId = job.payload_json?.journey_id;
          const model = job.payload_json?.model || "openai";
          const lookbackDays = Number(job.payload_json?.lookback_days || 7);
          if (!journeyId) throw new Error("Missing journey_id in payload");

          await processGuardiaoInsightsGenerateJob({ supabase, tenantId, journeyId, model, lookbackDays });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true });
          continue;
        }

        if (!caseId) throw new Error("Missing payload.case_id");

        if (job.type === "OCR_IMAGE") {
          const { data: att } = await supabase
            .from("case_attachments")
            .select("storage_path")
            .eq("tenant_id", tenantId)
            .eq("case_id", caseId)
            .eq("kind", "image")
            .order("created_at", { ascending: false })
            .limit(1)
            .maybeSingle();

          const imageUrl = att?.storage_path as string | undefined;
          if (!imageUrl) throw new Error("Missing image attachment");

          const ocr = await runOcrGoogleVision(imageUrl);
          if (!ocr.ok) {
            await supabase.from("decision_logs").insert({
              tenant_id: tenantId,
              case_id: caseId,
              agent_id: agentIdByKey.get("ocr_agent") ?? null,
              input_summary: "OCR_IMAGE",
              output_summary: "Falha no OCR",
              reasoning_public: "Não foi possível executar OCR com o provedor configurado.",
              why_json: { error: ocr.error },
              confidence_json: { overall: 0 },
              occurred_at: new Date().toISOString(),
            });
            // Keep job as failed
            await supabase.from("job_queue").update({ status: "failed", attempts: job.attempts + 1 }).eq("id", job.id);
            results.push({ id: job.id, ok: false, error: ocr.error });
            continue;
          }

          await supabase.from("case_fields").upsert({
            tenant_id: tenantId,
            case_id: caseId,
            key: "ocr_text",
            value_text: ocr.text,
            confidence: 0.85,
            source: "ocr",
            last_updated_by: "ocr_agent",
          });

          await supabase.from("timeline_events").insert({
            tenant_id: tenantId,
            case_id: caseId,
            event_type: "ocr_done",
            actor_type: "ai",
            message: "OCR concluído. Extraindo campos…",
            meta_json: {},
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("decision_logs").insert({
            tenant_id: tenantId,
            case_id: caseId,
            agent_id: agentIdByKey.get("ocr_agent") ?? null,
            input_summary: "Imagem do pedido",
            output_summary: `Texto OCR com ${ocr.text.length} caracteres`,
            reasoning_public: "Extraímos o texto do pedido para iniciar a extração estruturada de campos.",
            why_json: { provider: "google_vision" },
            confidence_json: { overall: 0.85 },
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);

          // enqueue extraction/validation
          await supabase.from("job_queue").insert({
            tenant_id: tenantId,
            type: "EXTRACT_FIELDS",
            idempotency_key: `EXTRACT_FIELDS:${caseId}:${Date.now()}`,
            payload_json: { case_id: caseId },
            status: "pending",
            run_after: new Date().toISOString(),
          });

          results.push({ id: job.id, ok: true });
          continue;
        }

        if (job.type === "EXTRACT_FIELDS") {
          const { data: ocrField } = await supabase
            .from("case_fields")
            .select("value_text")
            .eq("tenant_id", tenantId)
            .eq("case_id", caseId)
            .eq("key", "ocr_text")
            .maybeSingle();

          const rawText = (ocrField?.value_text as string | null) ?? "";
          const cleanedText = normalizeOcrTextForExtraction(rawText);
          const extracted = extractFieldsFromText(cleanedText);

          // Dedupe (Agroforte sales_order):
          // evita abrir mais de 1 caso com o MESMO cliente + MESMO total + MESMA lista de itens.
          // Regra: só considera itens estruturados quando tiver >= 1 item com descrição + qty + price.
          // Observação: só roda quando temos dados suficientes (para evitar falso-positivo).
          let targetCaseId = caseId;
          let mergedInto: string | null = null;

          try {
            const { data: cRow } = await supabase
              .from("cases")
              .select("id, meta_json")
              .eq("tenant_id", tenantId)
              .eq("id", caseId)
              .maybeSingle();

            const meta = (cRow as any)?.meta_json ?? {};
            const journeyKey = String(meta?.journey_key ?? "");
            const looksAgroforte = /\bagroforte\b/i.test(rawText);

            const clientKey =
              extracted.customer_code ||
              extracted.cpf ||
              (extracted.phone_raw ? toDigits(extracted.phone_raw) : "") ||
              extracted.name ||
              "";

            // Prefer structured case_items for fingerprint when we have at least 1 complete row.
            const { data: caseItems } = await supabase
              .from("case_items")
              .select("code,description,qty,price")
              .eq("case_id", caseId)
              .order("line_no", { ascending: true })
              .limit(200);

            const completeItems = (caseItems ?? []).filter((r: any) => {
              const desc = String(r?.description ?? "").trim();
              const qty = Number(r?.qty);
              const price = Number(r?.price);
              return desc && Number.isFinite(qty) && qty > 0 && Number.isFinite(price) && price >= 0;
            });

            const itemsSource = completeItems.length ? "case_items" : "ocr";

            const itemLinesForFp = completeItems.length
              ? completeItems.map((r: any) => {
                const code = String(r?.code ?? "").trim();
                const desc = String(r?.description ?? "").trim();
                const qty = Number(r?.qty);
                const price = Number(r?.price);
                return `${code ? `${code} ` : ""}${desc} | QTY:${qty} | PRICE:${price}`;
              })
              : (extracted.itemLines ?? []);

            const totalCentsFromItems = completeItems.length
              ? Math.round(
                completeItems.reduce((acc: number, r: any) => {
                  const qty = Number(r?.qty);
                  const price = Number(r?.price);
                  return acc + (Number.isFinite(qty) && Number.isFinite(price) ? qty * price : 0);
                }, 0) * 100
              )
              : null;

            const totalCents =
              totalCentsFromItems ??
              extractTotalCents(cleanedText) ??
              parsePtBrMoneyToCents(extracted.total_raw) ??
              null;

            const fingerprint =
              journeyKey === "sales_order" && looksAgroforte && clientKey && totalCents
                ? await computeSalesOrderFingerprint({
                  clientKey,
                  totalCents,
                  itemLines: itemLinesForFp,
                })
                : null;

            if (fingerprint) {
              const salesOrderClientKey = extracted.customer_code
                ? `customer_code:${normalizeKeyText(extracted.customer_code)}`
                : extracted.cpf
                  ? `cpf:${extracted.cpf}`
                  : extracted.phone_raw
                    ? `phone:${toDigits(extracted.phone_raw)}`
                    : extracted.name
                      ? `name:${normalizeKeyText(extracted.name)}`
                      : null;

              const nextMeta = {
                ...meta,
                sales_order_fingerprint: fingerprint,
                sales_order_client_key: salesOrderClientKey,
                sales_order_total_cents: totalCents,
                sales_order_items_source: itemsSource,
              };

              await supabase
                .from("cases")
                .update({ meta_json: nextMeta })
                .eq("tenant_id", tenantId)
                .eq("id", caseId);

              const { data: existing } = await supabase
                .from("cases")
                .select("id,updated_at")
                .eq("tenant_id", tenantId)
                .is("deleted_at", null)
                .contains("meta_json", { sales_order_fingerprint: fingerprint })
                .neq("id", caseId)
                .order("updated_at", { ascending: false })
                .limit(1)
                .maybeSingle();

              const keepId = (existing as any)?.id ? String((existing as any).id) : null;
              if (keepId) {
                await mergeDuplicateCase({
                  supabase,
                  tenantId,
                  duplicateCaseId: caseId,
                  keepCaseId: keepId,
                  fingerprint,
                });

                targetCaseId = keepId;
                mergedInto = keepId;
              }
            }
          } catch (e: any) {
            // Não falha o job por dedupe. Seguimos com a extração normal.
            console.warn(`[${fn}] dedupe_check_failed (ignored)`, { caseId, e: e?.message ?? String(e) });
          }

          // Se o case foi consolidado em outro, escrevemos os campos no case "keep".
          const { data: existingFields } = await supabase
            .from("case_fields")
            .select("key, source")
            .eq("case_id", targetCaseId);

          const sourceMap = new Map((existingFields || []).map((f: any) => [f.key, f.source]));

          const upserts: any[] = [];
          const pushSafe = (key: string, value: any, confidence: number) => {
            if (!value) return;
            const currentSource = sourceMap.get(key);
            // Don't overwrite admin or crm_generation fields
            if (currentSource === 'admin' || currentSource === 'crm_generation') return;

            upserts.push({ 
              tenant_id: tenantId, 
              case_id: targetCaseId, 
              key, 
              value_text: String(value), 
              confidence, 
              source: "ocr", 
              last_updated_by: "extract" 
            });
          };

          pushSafe("name", extracted.name, 0.75);
          pushSafe("customer_code", extracted.customer_code, 0.8);
          pushSafe("email", extracted.email, 0.75);
          pushSafe("address", extracted.address, 0.7);
          pushSafe("city", extracted.city, 0.75);
          pushSafe("cep", extracted.cep, 0.75);
          pushSafe("state", extracted.state, 0.7);
          pushSafe("uf", extracted.uf, 0.85);
          pushSafe("order_local", extracted.order_local, 0.75);
          pushSafe("order_date_text", extracted.order_date_text, 0.65);
          pushSafe("inscr_est", extracted.inscr_est, 0.6);
          pushSafe("cpf", extracted.cpf, extracted.cpf?.length === 11 ? 0.85 : 0.45);
          pushSafe("rg", extracted.rg, (extracted.rg?.length ?? 0) >= 7 ? 0.75 : 0.45);
          pushSafe("birth_date_text", extracted.birth_date_text, 0.75);
          pushSafe("phone", extracted.phone_raw, 0.75);
          pushSafe("total_raw", extracted.total_raw, 0.6);
          pushSafe("signature_present", extracted.signaturePresent ? "yes" : "no", 0.5);

          if (upserts.length) await supabase.from("case_fields").upsert(upserts);

          await supabase.from("decision_logs").insert({
            tenant_id: tenantId,
            case_id: targetCaseId,
            agent_id: agentIdByKey.get("validation_agent") ?? null,
            input_summary: "Texto OCR",
            output_summary: mergedInto ? "Campos extraídos e caso consolidado" : "Campos iniciais extraídos",
            reasoning_public: "Extração baseada em padrões (MVP). Se faltar algo, geraremos pendências ao vendedor.",
            why_json: {
              extracted_keys: upserts.map((u) => u.key),
              ocr_preprocess: cleanedText !== rawText ? "header_trim" : "none",
              merged_into: mergedInto,
            },
            confidence_json: { overall: 0.65 },
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);

          await supabase.from("job_queue").insert({
            tenant_id: tenantId,
            type: "VALIDATE_FIELDS",
            idempotency_key: `VALIDATE_FIELDS:${targetCaseId}:${Date.now()}`,
            payload_json: { case_id: targetCaseId },
            status: "pending",
            run_after: new Date().toISOString(),
          });

          results.push({ id: job.id, ok: true, mergedInto });
          continue;
        }

        if (job.type === "VALIDATE_FIELDS") {
          const { data: fields } = await supabase
            .from("case_fields")
            .select("key, value_text, value_json")
            .eq("tenant_id", tenantId)
            .eq("case_id", caseId);

          const fieldMap = new Map<string, any>();
          for (const f of fields ?? []) fieldMap.set(f.key, f.value_text ?? f.value_json);

          const missing: Array<{ type: string; question: string; required: boolean }> = [];

          const name = fieldMap.get("name");
          const cpf = fieldMap.get("cpf");
          const rg = fieldMap.get("rg");
          const birth = fieldMap.get("birth_date_text");
          const phone = fieldMap.get("phone");
          const location = fieldMap.get("location");
          const signature = fieldMap.get("signature_present");
          const totalRaw = fieldMap.get("total_raw");

          if (!name) missing.push({ type: "missing_field", question: "Qual é o NOME do cliente no pedido?", required: true });
          if (!cpf || String(cpf).length < 11) missing.push({ type: "missing_field", question: "Envie o CPF (somente números).", required: true });
          if (!rg || String(rg).length < 7) missing.push({ type: "missing_field", question: "Envie o RG (somente números).", required: true });
          if (!birth) missing.push({ type: "missing_field", question: "Qual é a data de nascimento? (dd/mm/aaaa)", required: true });
          // Required fields validation is now handled strictly by the Journey `status_configs`.
          // Hardcoded creation of pendencies has been removed from this core extraction logic.

          // Upsert pendencies (don't duplicate)
          for (const m of missing) {
            await supabase.from("pendencies").insert({
              tenant_id: tenantId,
              case_id: caseId,
              type: m.type,
              assigned_to_role: m.type === "leader_followup" ? "leader" : "vendor",
              question_text: m.question,
              required: m.required,
              status: "open",
              due_at: new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString(),
            });
          }

          const requiredOpen = (missing.filter((m) => m.required && m.type !== "leader_followup").length > 0) as boolean;

          await supabase.from("cases").update({
            state: requiredOpen ? "pending_vendor" : "ready_for_review",
            status: requiredOpen ? "in_progress" : "ready",
          }).eq("id", caseId);

          await supabase.from("decision_logs").insert({
            tenant_id: tenantId,
            case_id: caseId,
            agent_id: agentIdByKey.get("validation_agent") ?? null,
            input_summary: "Campos extraídos / respostas do vendedor",
            output_summary: requiredOpen ? "Pendências abertas para o vendedor" : "Pronto para revisão humana",
            reasoning_public: "O pedido só pode seguir quando os campos obrigatórios e a localização estiverem presentes.",
            why_json: { missing_required: missing.filter((m) => m.required).map((m) => m.question), missing_optional: missing.filter((m) => !m.required).map((m) => m.question) },
            confidence_json: { overall: requiredOpen ? 0.55 : 0.75 },
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true, requiredOpen });
          continue;
        }

        if (job.type === "ASK_PENDENCIES") {
          // Build a pendency list message
          const { data: c } = await supabase
            .from("cases")
            .select("assigned_user_id, meta_json")
            .eq("id", caseId)
            .maybeSingle();

          const meta = (c as any)?.meta_json ?? {};

          // Prefer sending to user when assigned; otherwise fallback to customer/counterpart phone.
          let toPhone: string | null = null;

          if (c?.assigned_user_id) {
            const { data: user } = await supabase
              .from("users_profile")
              .select("phone_e164")
              .eq("user_id", c.assigned_user_id)
              .maybeSingle();

            toPhone = (user as any)?.phone_e164 ?? null;
          }

          if (!toPhone) {
            const fallback =
              (meta?.customer_phone as string | undefined) ??
              (meta?.counterpart_phone as string | undefined) ??
              (meta?.phone as string | undefined) ??
              null;
            toPhone = fallback && String(fallback).trim() ? String(fallback).trim() : null;
          }

          if (!toPhone) {
            // Last resort: look for an extracted phone field
            const { data: cf } = await supabase
              .from("case_fields")
              .select("value_text")
              .eq("tenant_id", tenantId)
              .eq("case_id", caseId)
              .in("key", ["whatsapp", "phone", "customer_phone"])
              .order("updated_at", { ascending: false })
              .limit(1)
              .maybeSingle();
            toPhone = (cf as any)?.value_text ? String((cf as any).value_text).trim() : null;
          }

          if (!toPhone) throw new Error("Case has no recipient phone (vendor/customer)");

          const { data: pends } = await supabase
            .from("pendencies")
            .select("id, question_text, required")
            .eq("tenant_id", tenantId)
            .eq("case_id", caseId)
            .eq("assigned_to_role", "vendor")
            .eq("status", "open")
            .order("created_at", { ascending: true });

          if (!pends?.length) {
            await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
            results.push({ id: job.id, ok: true, note: "no pendencies" });
            continue;
          }

          const list = pends
            .map((p: any, idx: number) => `${idx + 1}) ${p.question_text}${p.required ? "" : " (opcional)"}`)
            .join("\n");

          const msg = `Byfrost.ia — Pendências do pedido:\n\n${list}\n\nVocê pode responder por texto ou áudio (MVP).`;

          const { data: inst } = await supabase
            .from("wa_instances")
            .select("id, phone_number")
            .eq("tenant_id", tenantId)
            .eq("status", "active")
            .order("created_at", { ascending: true })
            .limit(1)
            .maybeSingle();

          if (inst?.id) {
            await supabase.from("wa_messages").insert({
              tenant_id: tenantId,
              instance_id: inst.id,
              case_id: caseId,
              direction: "outbound",
              from_phone: inst.phone_number ?? null,
              to_phone: toPhone,
              type: "text",
              body_text: msg,
              payload_json: { kind: "pendency_list", case_id: caseId },
              correlation_id: `case:${caseId}`,
              occurred_at: new Date().toISOString(),
            });

            await supabase.from("usage_events").insert({
              tenant_id: tenantId,
              type: "message",
              qty: 1,
              ref_type: "wa_message",
              meta_json: { direction: "outbound", wa_type: "text", kind: "pendency_list" },
              occurred_at: new Date().toISOString(),
            });
          }

          await supabase.from("timeline_events").insert({
            tenant_id: tenantId,
            case_id: caseId,
            event_type: "pendencies_asked",
            actor_type: "ai",
            message: "Pendências enviadas (lista).",
            meta_json: { count: pends.length, to: toPhone },
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("decision_logs").insert({
            tenant_id: tenantId,
            case_id: caseId,
            agent_id: agentIdByKey.get("comms_agent") ?? null,
            input_summary: "Pendências abertas",
            output_summary: "Lista de perguntas preparada e registrada na outbox",
            reasoning_public: "Mantemos a conversa sempre em formato de lista para reduzir ambiguidades.",
            why_json: { pendency_count: pends.length },
            confidence_json: { overall: 0.8 },
            occurred_at: new Date().toISOString(),
          });

          await supabase.from("job_queue").update({ status: "done" }).eq("id", job.id);
          results.push({ id: job.id, ok: true });
          continue;
        }


        // Unknown job type
        await supabase.from("job_queue").update({ status: "failed", attempts: job.attempts + 1 }).eq("id", job.id);
        results.push({ id: job.id, ok: false, error: `Unknown job type ${job.type}` });
      } catch (e: any) {
        console.error(`[${fn}] job failed`, { id: job.id, type: job.type, error: e?.message ?? String(e) });

        if (job.type === "FINANCIAL_INGESTION") {
          const ingestionJobId = String(job.payload_json?.ingestion_job_id ?? "").trim();
          if (ingestionJobId) {
            await supabase
              .from("ingestion_jobs")
              .update({ status: "failed", error_log: String(e?.message ?? e) })
              .eq("id", ingestionJobId);
          }
        }

        await supabase.from("job_queue").update({ status: "failed", attempts: job.attempts + 1 }).eq("id", job.id);
        results.push({ id: job.id, ok: false, error: e?.message ?? String(e) });
      }
    }

    debug.processed = results.length;
    return new Response(JSON.stringify({ ok: true, processed: results.length, results, debug }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (e) {
    console.error("[jobs-processor] unhandled", { error: (e as any)?.message ?? String(e) });
    return new Response(JSON.stringify({ ok: false, error: (e as any)?.message, debug: { error: (e as any)?.message } }), { status: 500, headers: corsHeaders });
  }
});

type EmbeddingOptions = {
  model?: string;
};

const DEFAULT_EMBEDDINGS_MODEL = "text-embedding-3-small";
const EMBEDDING_DIM = 1536;

function xorshift32(seed: number) {
  let x = seed | 0;
  return () => {
    x ^= x << 13;
    x ^= x >>> 17;
    x ^= x << 5;
    // -> [0, 1)
    return ((x >>> 0) / 0xffffffff) as number;
  };
}

function seedFromText(text: string) {
  let h = 2166136261;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}

async function openAIEmbed({
  text,
  model,
}: {
  text: string;
  model: string;
}): Promise<number[]> {
  const apiKey = Deno.env.get("AI_API_KEY") ?? "";
  if (!apiKey) throw new Error("Missing AI_API_KEY");

  const res = await fetch("https://api.openai.com/v1/embeddings", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      input: text,
    }),
  });

  const json = await res.json().catch(() => null);
  if (!res.ok || !json) {
    throw new Error(`OpenAI embeddings failed: ${res.status}`);
  }

  const emb = json?.data?.[0]?.embedding;
  if (!Array.isArray(emb)) throw new Error("OpenAI embeddings: invalid response");
  return emb as number[];
}

export async function embedText(text: string, opts: EmbeddingOptions = {}) {
  const provider = (Deno.env.get("AI_PROVIDER") ?? "").toLowerCase();
  const model = opts.model ?? Deno.env.get("EMBEDDINGS_MODEL") ?? DEFAULT_EMBEDDINGS_MODEL;

  if (provider === "openai") {
    const emb = await openAIEmbed({ text, model });
    return emb;
  }

  // Deterministic fallback (no vendor hardcode) — useful for local/dev without keys.
  const rand = xorshift32(seedFromText(`${provider}:${model}:${text}`));
  const out = new Array<number>(EMBEDDING_DIM);
  for (let i = 0; i < EMBEDDING_DIM; i++) out[i] = (rand() - 0.5) * 0.2;
  return out;
}

export function toVectorString(vec: number[]) {
  // PostgREST vector can be inserted as a string like: "[0.1,0.2,...]"
  return `[${vec.map((n) => (Number.isFinite(n) ? n.toFixed(8) : "0")).join(",")}]`;
}

import { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

export async function checkTenantAILimits(tenantId: string, supabaseAdmin: SupabaseClient): Promise<void> {
  // 1. Fetch current plan limit
  const { data: tp, error: tpErr } = await supabaseAdmin
    .from("tenant_plans")
    .select("plans ( limits_json )")
    .eq("tenant_id", tenantId)
    .is("deleted_at", null)
    .order("created_at", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (tpErr) {
    console.error(`[checkTenantAILimits] Error fetching tenant plans: ${tpErr.message}`);
    // Non-blocking if there's a DB issue just to not break production unexpectedly,
    // but ideally we should throw. Let's just log and allow for now.
    return;
  }

  // Get the limit. If not found or null, we treat as unlimited.
  const limitStr = (tp?.plans as any)?.limits_json?.ai_tokens;
  if (limitStr === undefined || limitStr === null) {
    return; // Unlimited
  }

  const limitTokens = Number(limitStr);
  if (isNaN(limitTokens) || limitTokens <= 0) {
    return; // Unlimited or invalid limit
  }

  // 2. Fetch current month's usage
  const periodStart = new Date();
  periodStart.setDate(1);
  const periodStartDate = periodStart.toISOString().slice(0, 10);

  const { data: counter, error: counterErr } = await supabaseAdmin
    .from("usage_counters")
    .select("metrics_json")
    .eq("tenant_id", tenantId)
    .eq("period_start", periodStartDate)
    .maybeSingle();

  if (counterErr) {
    console.error(`[checkTenantAILimits] Error fetching usage_counters: ${counterErr.message}`);
    return; // Allow on error
  }

  const currentUsage = Number((counter?.metrics_json as any)?.ai_tokens || 0);

  // 3. Compare and throw if exceeded
  if (currentUsage >= limitTokens) {
    throw new Error("Plan limits exceeded");
  }
}

export async function logAITokenUsage(
  tenantId: string,
  tokensUsed: number,
  description: string,
  model: string,
  supabaseAdmin: SupabaseClient,
  refType: string = "guardiao_insight",
  refId: string | null = null
) {
  if (tokensUsed <= 0) return;

  const costUsd = tokensUsed * 0.0000003;
  const { error: usageErr } = await supabaseAdmin.from("usage_events").insert({
    tenant_id: tenantId,
    type: "ai_token",
    qty: tokensUsed,
    ref_type: refType,
    ref_id: refId,
    occurred_at: new Date().toISOString(),
    meta_json: {
      description,
      cost_usd: costUsd,
      model: model,
    },
  });

  if (usageErr) {
    console.error("[logAITokenUsage] Failed to insert usage_event:", usageErr);
  }

  const periodStart = new Date();
  periodStart.setDate(1);
  const periodStartDate = periodStart.toISOString().slice(0, 10);

  const { data: counter } = await supabaseAdmin
    .from("usage_counters")
    .select("id, metrics_json")
    .eq("tenant_id", tenantId)
    .eq("period_start", periodStartDate)
    .maybeSingle();

  if (counter) {
    const currentTokens = Number((counter.metrics_json as any)?.ai_tokens || 0);
    await supabaseAdmin
      .from("usage_counters")
      .update({
        metrics_json: { ...counter.metrics_json, ai_tokens: currentTokens + tokensUsed },
      })
      .eq("id", counter.id);
  } else {
    // Calculate last day of the month
    const periodEnd = new Date(periodStart.getFullYear(), periodStart.getMonth() + 1, 0);
    const periodEndDate = periodEnd.toISOString().slice(0, 10);

    await supabaseAdmin.from("usage_counters").insert({
      tenant_id: tenantId,
      period_start: periodStartDate,
      period_end: periodEndDate,
      metrics_json: { ai_tokens: tokensUsed },
    });
  }
}

export const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type, x-requested-with, prefer",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
