export function withCors(resp: Response) {
  const headers = new Headers(resp.headers);
  for (const [k, v] of Object.entries(corsHeaders)) headers.set(k, v);
  return new Response(resp.body, { ...resp, headers });
}

export async function sha256Hex(text: string) {
  const data = new TextEncoder().encode(text);
  const hash = await crypto.subtle.digest("SHA-256", data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

export async function fetchAsBase64(url: string) {
  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`Failed to fetch media: ${res.status}`);
  }
  const buf = new Uint8Array(await res.arrayBuffer());
  let binary = "";
  const chunkSize = 0x8000;
  for (let i = 0; i < buf.length; i += chunkSize) {
    binary += String.fromCharCode(...buf.slice(i, i + chunkSize));
  }
  return btoa(binary);
}

// Shared encryption helpers for Edge Functions (server-side only)
// Tokens/secrets MUST be encrypted before storing.

function b64encode(bytes: Uint8Array) {
  let binary = "";
  const chunkSize = 0x8000;
  for (let i = 0; i < bytes.length; i += chunkSize) {
    binary += String.fromCharCode(...bytes.slice(i, i + chunkSize));
  }
  return btoa(binary);
}

function b64decode(s: string) {
  const bin = atob(s);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

async function keyFromSecret(secret: string) {
  const hash = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(secret));
  return crypto.subtle.importKey("raw", hash, { name: "AES-GCM" }, false, ["encrypt", "decrypt"]);
}

export async function encryptText(plaintext: string) {
  const secret = Deno.env.get("APP_TOKEN_ENCRYPTION_KEY") ?? "";
  if (!secret) throw new Error("Missing APP_TOKEN_ENCRYPTION_KEY secret");

  const key = await keyFromSecret(secret);
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const pt = new TextEncoder().encode(plaintext);
  const ct = new Uint8Array(await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, pt));

  const packed = new Uint8Array(iv.length + ct.length);
  packed.set(iv, 0);
  packed.set(ct, iv.length);

  return `v1:${b64encode(packed)}`;
}

export async function decryptText(ciphertext: string) {
  const secret = Deno.env.get("APP_TOKEN_ENCRYPTION_KEY") ?? "";
  if (!secret) throw new Error("Missing APP_TOKEN_ENCRYPTION_KEY secret");

  const raw = String(ciphertext ?? "");
  const [, payload] = raw.split("v1:");
  if (!payload) throw new Error("Invalid ciphertext");

  const bytes = b64decode(payload);
  if (bytes.length < 13) throw new Error("Invalid ciphertext");

  const key = await keyFromSecret(secret);
  const iv = bytes.slice(0, 12);
  const ct = bytes.slice(12);
  const pt = new Uint8Array(await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, ct));
  return new TextDecoder().decode(pt);
}

// Shared helper: Google service-account OAuth access token via JWT assertion.
// Used by Edge Functions (Deno) to call Google APIs that require OAuth (e.g. Document AI).

function base64UrlEncode(input: string | Uint8Array) {
  const bytes = typeof input === "string" ? new TextEncoder().encode(input) : input;
  let bin = "";
  const chunk = 0x8000;
  for (let i = 0; i < bytes.length; i += chunk) {
    bin += String.fromCharCode(...bytes.slice(i, i + chunk));
  }
  const b64 = btoa(bin);
  return b64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function pemToArrayBuffer(pem: string) {
  const b64 = pem
    .replace(/-----BEGIN [^-]+-----/g, "")
    .replace(/-----END [^-]+-----/g, "")
    .replace(/\s+/g, "");
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}

async function importPrivateKeyFromServiceAccount(sa: any) {
  const pkPem = sa?.private_key;
  if (!pkPem) throw new Error("Missing private_key in service account JSON");
  const pkcs8 = pemToArrayBuffer(String(pkPem));
  return crypto.subtle.importKey(
    "pkcs8",
    pkcs8,
    { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
    false,
    ["sign"]
  );
}

export async function getGoogleAccessToken(params: {
  serviceAccountJson: string;
  scopes: string[];
}) {
  const sa = JSON.parse(params.serviceAccountJson);
  const clientEmail = sa?.client_email;
  if (!clientEmail) throw new Error("Missing client_email in service account JSON");

  const key = await importPrivateKeyFromServiceAccount(sa);
  const now = Math.floor(Date.now() / 1000);

  const header = { alg: "RS256", typ: "JWT" };
  const claim = {
    iss: clientEmail,
    scope: params.scopes.join(" "),
    aud: "https://oauth2.googleapis.com/token",
    iat: now,
    exp: now + 3600,
  };

  const signingInput = `${base64UrlEncode(JSON.stringify(header))}.${base64UrlEncode(JSON.stringify(claim))}`;
  const signature = new Uint8Array(
    await crypto.subtle.sign(
      { name: "RSASSA-PKCS1-v1_5" },
      key,
      new TextEncoder().encode(signingInput)
    )
  );

  const jwt = `${signingInput}.${base64UrlEncode(signature)}`;

  const body = new URLSearchParams({
    grant_type: "urn:ietf:params:oauth:grant-type:jwt-bearer",
    assertion: jwt,
  });

  const res = await fetch("https://oauth2.googleapis.com/token", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });

  const json = await res.json().catch(() => null);
  if (!res.ok || !json?.access_token) {
    throw new Error(`OAuth token error: ${res.status}`);
  }

  return String(json.access_token);
}

import { getGoogleAccessToken } from "./googleAuth.ts";

export type DocAIProcessResult = {
  document?: any;
  [k: string]: any;
};

function inferDocAiHostFromProcessorName(processorName: string) {
  // processorName format: projects/.../locations/<location>/processors/...
  const m = String(processorName ?? "").match(/\/locations\/([^/]+)\//i);
  const location = m?.[1] ? String(m[1]).trim() : "";

  // Use regional endpoint whenever we can infer a location.
  // This avoids 404s that can happen when calling a regional processor via the global host.
  if (location) return `${location}-documentai.googleapis.com`;

  return "documentai.googleapis.com";
}

export async function processWithGoogleDocumentAI(input: {
  processorName: string; // full resource name: projects/.../locations/.../processors/...
  serviceAccountJson: string;
  contentBase64: string;
  mimeType: string;
}) {
  const token = await getGoogleAccessToken({
    serviceAccountJson: input.serviceAccountJson,
    scopes: ["https://www.googleapis.com/auth/cloud-platform"],
  });

  const host = inferDocAiHostFromProcessorName(input.processorName);
  const endpoint = `https://${host}/v1/${input.processorName}:process`;

  const payload = {
    rawDocument: {
      content: input.contentBase64,
      mimeType: input.mimeType,
    },
  };

  const res = await fetch(endpoint, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });

  const json = (await res.json().catch(() => null)) as DocAIProcessResult | null;
  if (!res.ok || !json) {
    const errMsg = (json as any)?.error?.message ? String((json as any).error.message) : "";
    const errStatus = (json as any)?.error?.status ? String((json as any).error.status) : "";
    const suffix = [errStatus, errMsg].filter(Boolean).join(" - ");
    throw new Error(`Document AI error: ${res.status}${suffix ? ` (${suffix})` : ""}`);
  }

  return json;
}

export function docAiTextFromAnchor(doc: any, anchor: any) {
  const text = String(doc?.text ?? "");
  const segs = anchor?.textSegments ?? [];
  if (!Array.isArray(segs) || !segs.length) return "";

  let out = "";
  for (const s of segs) {
    const start = Number(s?.startIndex ?? 0);
    const end = Number(s?.endIndex ?? 0);
    if (!Number.isFinite(start) || !Number.isFinite(end) || end <= start) continue;
    out += text.slice(start, end);
  }
  return out;
}

export function docAiExtractFormFields(doc: any) {
  const out: Array<{ label: string; value: string }> = [];
  const pages = doc?.pages ?? [];
  for (const p of pages) {
    const fields = p?.formFields ?? [];
    for (const f of fields) {
      const label = docAiTextFromAnchor(doc, f?.fieldName?.textAnchor);
      const value = docAiTextFromAnchor(doc, f?.fieldValue?.textAnchor);
      const l = String(label ?? "").replace(/\s+/g, " ").trim();
      const v = String(value ?? "").replace(/\s+/g, " ").trim();
      if (l || v) out.push({ label: l, value: v });
    }
  }
  return out;
}

export function docAiExtractTables(doc: any) {
  const pages = doc?.pages ?? [];
  const tables: any[] = [];
  for (const p of pages) {
    for (const t of p?.tables ?? []) {
      tables.push(t);
    }
  }
  return tables;
}

type ChatMessage = { role: "system" | "user"; content: string };

function seededPick(text: string, options: string[]) {
  let h = 2166136261;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  const idx = (h >>> 0) % options.length;
  return options[idx];
}

async function openAIChat({
  messages,
  model,
  temperature,
}: {
  messages: ChatMessage[];
  model: string;
  temperature: number;
}): Promise<{ text: string; tokensUsed: number }> {
  const apiKey = Deno.env.get("OPENAI_API_KEY") ?? "";
  if (!apiKey) throw new Error("Missing OPENAI_API_KEY");

  const res = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      temperature,
      messages,
    }),
  });

  const json = await res.json().catch(() => null);
  if (!res.ok || !json) {
    throw new Error(`OpenAI chat failed: ${res.status}`);
  }

  const text = json?.choices?.[0]?.message?.content;
  const tokensUsed = json?.usage?.total_tokens || 1000;
  if (!text || typeof text !== "string") throw new Error("OpenAI chat: invalid response");
  return { text, tokensUsed };
}

export async function generateText({
  messages,
  fallback,
}: {
  messages: ChatMessage[];
  fallback: () => string;
}): Promise<{ text: string; provider: string; tokensUsed: number }>
{
  const provider = (Deno.env.get("AI_PROVIDER") ?? "openai").toLowerCase();

  if (provider === "openai") {
    const model = Deno.env.get("AI_MODEL") ?? "gpt-4o-mini";
    const temperature = Number(Deno.env.get("AI_TEMPERATURE") ?? 0.6);
    const { text, tokensUsed } = await openAIChat({ messages, model, temperature });
    return { text, provider: "openai", tokensUsed };
  }

  // Deterministic fallback: keeps product usable without keys.
  const txt = fallback();
  return { text: txt, provider: provider || "fallback", tokensUsed: 0 };
}

